  // ── HEALTH: First Aid ──
  add(0,"First Aid","If bitten by a snake, you should:",["Keep calm, immobilize the limb, and get to a hospital immediately","Suck out the venom","Apply a tourniquet tightly","Cut the wound to drain venom"],0,"Keep the victim calm and still. Immobilize the bitten limb and seek emergency medical care.","Snake bite: stay calm, immobilize, hospital ASAP. Never suck/cut.");
  add(0,"First Aid","The RICE method for sprains stands for:",["Rest, Ice, Compression, Elevation","Run, Ice, Compress, Eat","Relax, Immerse, Cold, Exercise","Rub, Ice, Cover, Elevate"],0,"RICE reduces swelling and pain. Rest the injury, apply Ice, use Compression, and Elevate the limb.","Sprain? Remember RICE: Rest, Ice, Compression, Elevation.");
  add(0,"First Aid","A knocked-out permanent tooth should be stored in:",["Milk or the person's own saliva until you reach a dentist","Warm water","Dry tissue paper","Antiseptic liquid"],0,"Milk keeps tooth cells alive for reimplantation. See a dentist within 30 minutes for best results.","Knocked-out tooth → store in milk, dentist within 30 min.");
  add(0,"First Aid","If someone is having an asthma attack without an inhaler:",["Help them sit upright, stay calm, and call emergency services","Make them lie flat","Have them breathe into a paper bag","Give them cold water"],0,"Sitting upright opens airways. Keep them calm. Call 112 if symptoms worsen or inhaler is unavailable.","Asthma attack: sit upright, stay calm, call 112 if no inhaler.");
  add(0,"First Aid","A person in shock after an injury typically has:",["Cool, clammy, pale skin with rapid pulse","Hot, flushed skin","Normal skin color","Dry, warm skin"],0,"Shock reduces blood flow to organs. Lay the person down, elevate legs, keep warm, and call emergency.","Shock: cool/clammy skin, rapid pulse. Lay down, elevate legs, call 112.");

  // ── HEALTH: Nutrition ──
  add(0,"Nutrition","Ragi (finger millet) is especially rich in:",["Calcium — among the highest of any cereal grain","Vitamin D","Protein — more than chicken","Fat — more than butter"],0,"Ragi has 344mg calcium per 100g, making it one of the best non-dairy calcium sources.","Ragi: highest calcium among cereals. Great for bones.");
  add(0,"Nutrition","Iron absorption from food is enhanced by consuming it with:",["Vitamin C-rich foods like citrus fruits","Tea or coffee","Milk","Soda"],0,"Vitamin C converts iron to a form that's easier to absorb. Eat oranges or amla with iron-rich meals.","Boost iron absorption: eat Vitamin C foods with iron-rich meals.");
  add(0,"Nutrition","The Mediterranean diet emphasizes:",["Olive oil, fish, whole grains, fruits, and vegetables","Red meat and butter","Processed foods and soda","Deep-fried foods and white bread"],0,"This diet is associated with lower heart disease, stroke, and diabetes risk in multiple studies.","Mediterranean diet: olive oil, fish, whole grains → proven heart benefits.");
  add(0,"Nutrition","Turmeric's active compound curcumin is beneficial because it has:",["Anti-inflammatory and antioxidant properties","High calorie content","Caffeine-like stimulant effects","Antibiotic properties that replace medicine"],0,"Curcumin reduces inflammation and acts as an antioxidant. Better absorbed with black pepper (piperine).","Turmeric + black pepper = better absorption of curcumin's benefits.");
  add(0,"Nutrition","Overnight soaking of pulses and grains before cooking:",["Improves digestibility and reduces cooking time","Removes all protein","Has no effect whatsoever","Makes them toxic"],0,"Soaking breaks down phytic acid, improving mineral absorption and making nutrients more bioavailable.","Soak dals overnight: better digestion, more nutrients, faster cooking.");

  // ── HEALTH: Diseases ──
  add(0,"Diseases","Chikungunya is transmitted through:",["Aedes mosquito bites, the same mosquito that spreads dengue","Contaminated drinking water","Direct person-to-person contact","Airborne droplets"],0,"Chikungunya causes severe joint pain and fever. Prevention: eliminate stagnant water where Aedes breeds.","Chikungunya: same Aedes mosquito as dengue. Eliminate stagnant water.");
  add(0,"Diseases","Pneumonia is an infection of the:",["Lungs, where air sacs fill with fluid or pus causing breathing difficulty","Stomach lining","Kidneys","Skin"],0,"Pneumonia can be caused by bacteria, viruses, or fungi. Symptoms: cough, fever, difficulty breathing.","Pneumonia: lung infection. Cough + fever + breathlessness = see doctor.");
  add(0,"Diseases","Appendicitis pain typically:",["Starts around the navel and moves to the lower right abdomen","Stays in the chest","Affects only the legs","Occurs only in the head"],0,"Lower right abdominal pain with fever and nausea may indicate appendicitis — a surgical emergency.","Pain moving to lower right abdomen = possible appendicitis. ER now.");
  add(0,"Diseases","PCOS (Polycystic Ovary Syndrome) affects:",["Women of reproductive age, causing hormonal imbalance","Only post-menopausal women","Only men","Only children"],0,"PCOS causes irregular periods, excess androgen, and polycystic ovaries. It affects 1 in 10 women.","PCOS: affects 1 in 10 women. Treatable with lifestyle changes and medication.");
  add(0,"Diseases","Rabies can be prevented after an animal bite by:",["Immediately washing the wound with soap and water and getting post-exposure vaccination","Applying turmeric paste alone","Ignoring it if the animal looked healthy","Tying a cloth tightly around the bite"],0,"Wash the wound thoroughly for 15 minutes with soap and water, then get anti-rabies vaccine immediately.","Animal bite: wash with soap 15 min, get rabies vaccine immediately.");

  // ── HEALTH: Body ──
  add(0,"Body","The strongest bone in the human body is the:",["Femur (thighbone)","Skull","Spine","Rib"],0,"The femur is the longest, strongest bone, supporting your entire body weight during walking and running.","Femur: your body's strongest bone. Supports your entire weight.");
  add(0,"Body","The funny bone sensation comes from hitting the:",["Ulnar nerve at the elbow, not an actual bone","Humerus bone","Radius bone","Elbow cartilage"],0,"The ulnar nerve runs close to the skin near the elbow. Hitting it causes tingling in the ring and little fingers.","'Funny bone' = ulnar nerve. Not a bone at all!");
  add(0,"Body","Taste buds can detect five basic tastes:",["Sweet, sour, salty, bitter, and umami (savory)","Only sweet and sour","Sweet, sour, salty, and spicy","Only sweet, salty, and bitter"],0,"Umami (savory) was identified as the 5th taste in 1908. It's found in foods like tomatoes, cheese, and soy sauce.","5 basic tastes: sweet, sour, salty, bitter, umami. Spicy is pain, not taste.");
  add(0,"Body","The human heart pumps blood through approximately:",["100,000 km of blood vessels","1,000 km of blood vessels","100 km of blood vessels","10 km of blood vessels"],0,"If laid end to end, your blood vessels would circle Earth more than twice. The heart beats ~100,000 times daily.","100,000 km of blood vessels in your body — heart beats 100,000 times/day.");

  // ── HEALTH: Mental ──
  add(0,"Mental","The 5-4-3-2-1 grounding technique for anxiety involves noticing:",["5 things you see, 4 you touch, 3 you hear, 2 you smell, 1 you taste","5 fears you have","5 people around you","5 problems to solve"],0,"This sensory technique redirects focus from anxiety to the present moment, breaking the panic cycle.","Anxiety? Try 5-4-3-2-1: see 5, touch 4, hear 3, smell 2, taste 1.");
  add(0,"Mental","Burnout is characterized by:",["Emotional exhaustion, cynicism, and reduced effectiveness at work","High energy and enthusiasm","Only physical tiredness","Being lazy"],0,"Burnout is a real medical condition from chronic workplace stress. It requires rest and boundary-setting.","Burnout: exhaustion + cynicism + reduced effectiveness. Take it seriously.");

  // ── SAFETY: Road ──
  add(1,"Road","The most common distraction causing driving accidents is:",["Using a mobile phone while driving","Adjusting mirrors","Talking to passengers calmly","Changing radio stations"],0,"Texting while driving makes a crash 23x more likely. Even hands-free calls reduce attention significantly.","Phone use while driving: 23x more crash risk. Put it away.");
  add(1,"Road","Hydroplaning occurs when:",["Water builds between tires and road, causing complete loss of traction","Tires overheat in summer","Brakes stop working due to heat","Engine overheats"],0,"Hydroplaning happens at speeds above 55 km/h on wet roads. Reduce speed and avoid sudden braking.","Wet roads: slow down. Hydroplaning starts around 55 km/h.");
  add(1,"Road","If your car starts to skid on a wet road:",["Ease off the accelerator gently and steer in the direction you want to go","Brake hard immediately","Accelerate to power through","Turn the wheel sharply in the opposite direction"],0,"Hard braking or sharp steering worsens a skid. Gentle corrections let tires regain traction.","Skidding: ease off gas, steer where you want to go. Don't brake hard.");
  add(1,"Road","Driving with worn-out tires is dangerous mainly because:",["Braking distance increases dramatically, especially on wet roads","Fuel consumption increases slightly","The car looks old","It only affects ride comfort"],0,"Worn tires have less grip. On wet roads, stopping distance can increase by 50% or more.","Replace tires before tread wears below 1.6mm. Your life depends on it.");
  add(1,"Road","Child car seats reduce fatal injury risk in toddlers by:",["About 71%","About 10%","About 30%","About 50%"],0,"Properly installed child seats dramatically reduce death and serious injury in car crashes.","Child car seats: 71% reduction in fatal injuries. Always use one.");
  add(1,"Road","In foggy conditions, you should use:",["Low beam headlights and fog lights, and reduce speed","High beam headlights for maximum visibility","No lights at all","Only hazard lights"],0,"High beams reflect off fog and reduce visibility. Low beams and fog lights penetrate better.","Fog: use LOW beams + fog lights. High beams make it WORSE.");

  // ── SAFETY: Cyber ──
  add(1,"Cyber","If your social media account is hacked, the first step is:",["Change your password immediately and enable two-factor authentication","Create a new account","Post about it on the hacked account","Ignore it and wait"],0,"Quick password change prevents further unauthorized access. Enable 2FA to prevent future hacking.","Hacked account: change password immediately, enable 2FA, review activity.");
  add(1,"Cyber","Before installing any app, you should check:",["Reviews, permissions requested, developer reputation, and download count","Only the app icon design","Nothing — all apps on stores are safe","Only the file size"],0,"Malicious apps exist even on official stores. Check what permissions the app demands and why.","Check app permissions before installing. Calculator doesn't need your contacts.");
  add(1,"Cyber","When shopping online, a secure payment page should show:",["https:// with a lock icon in the browser address bar","Only http:// is needed","No specific security indicators","A green background color"],0,"HTTPS encrypts your payment data. But also verify the website is legitimate — scam sites use HTTPS too.","Look for https:// + lock icon. But also verify the website is real.");
  add(1,"Cyber","A 'money mule' scheme involves:",["Unknowingly allowing your bank account to be used for laundering stolen money","A type of legitimate investment","Saving money wisely","Cryptocurrency mining"],0,"Criminals recruit people to receive and transfer stolen funds. You become criminally liable even if unaware.","Never let strangers use your bank account. You could be a money mule.");

  // ── SAFETY: Fire ──
  add(1,"Fire","The leading cause of fire deaths is:",["Smoke inhalation, not burns","Direct burns from flames","Structural collapse","Falling debris"],0,"Toxic smoke kills more people than flames. This is why staying low and crawling is critical.","Smoke kills more than fire. Stay LOW — breathable air is near the floor.");
  add(1,"Fire","Before opening a closed door during a fire:",["Feel the door and handle with the back of your hand for heat","Kick it open immediately","Look through the keyhole","Open it as quickly as possible"],0,"A hot door means fire on the other side. Use the back of your hand so you don't burn your palm.","Hot door = fire behind it. Never open. Find another exit route.");

  // ── SAFETY: Scam ──
  add(1,"Scam","A 'digital arrest' scam involves callers claiming to be:",["Police or CBI officers threatening arrest unless you pay immediately","Bank managers offering low-interest loans","Insurance agents with good deals","Telecom companies offering upgrades"],0,"No real police officer demands money over the phone. Official legal processes involve physical court orders.","No legitimate authority demands money over phone. 'Digital arrest' = SCAM.");
  add(1,"Scam","QR code payment scams work because victims don't realize:",["Scanning a QR code initiates payment FROM your account, not a receipt TO it","QR codes are always safe and verified","QR codes cannot transfer money","QR codes only work on certain phones"],0,"Scammers say 'scan this to RECEIVE money' but scanning actually SENDS money from your account.","QR codes are for PAYING. You can never RECEIVE money by scanning one.");
  add(1,"Scam","Investment scams typically promise:",["Guaranteed extremely high returns with zero risk","Market-rate returns with normal risk","Low returns with government backing","No returns at all"],0,"No legitimate investment guarantees high returns with zero risk. If it sounds too good to be true, it is.","'Guaranteed high returns + zero risk' = SCAM. Every single time.");

  // ── SAFETY: Disaster ──
  add(1,"Disaster","An emergency preparedness kit should contain supplies for at least:",["72 hours (3 days)","12 hours","1 week minimum","1 month"],0,"Kit should include water, food, medications, flashlight, radio, first aid, and copies of documents.","Emergency kit: water, food, meds, flashlight for 72 hours minimum.");
  add(1,"Disaster","The eye of a cyclone is:",["A calm, clear area at the center surrounded by the most violent winds","The most dangerous part","The weakest part of the storm","The fastest-moving part"],0,"The eye is deceptively calm. The eyewall surrounding it has the most destructive winds.","Cyclone eye is calm but temporary. The worst winds surround it.");

  // ── MONEY ──
  add(2,"Banking","NEFT transfers are processed in:",["Batches at regular intervals throughout the day","Real-time instantly like IMPS","Once a week","Once a month"],0,"NEFT settles in half-hourly batches. For instant transfers, use IMPS or UPI.","NEFT: batch processing. IMPS/UPI: instant. RTGS: real-time for large amounts.");
  add(2,"Banking","A demand draft (DD) differs from a cheque because:",["A DD is prepaid and cannot bounce, unlike a personal cheque","They are identical","DD is cheaper","Cheques are safer"],0,"Since a DD is prepaid by the sender's bank, the recipient is guaranteed payment.","DD cannot bounce — it's prepaid by the bank. Safer than personal cheques.");
  add(2,"Investment","ELSS mutual funds have a lock-in period of:",["3 years — the shortest among all 80C tax-saving instruments","1 year","5 years","7 years"],0,"ELSS offers equity exposure with tax benefits. PPF locks for 15 years, NSC for 5 years — ELSS is shortest.","ELSS: 3-year lock-in. Shortest tax-saving lock-in + equity growth potential.");
  add(2,"Investment","Dollar cost averaging through SIP helps because:",["You buy more units when prices are low and fewer when high, averaging cost","You always buy at the lowest price","It guarantees profits regardless of market","It eliminates all market risk"],0,"SIP removes the need to time the market. Over time, you benefit from rupee cost averaging.","SIP: consistency beats timing. More units when cheap, fewer when expensive.");
  add(2,"Insurance","A health insurance claim settlement ratio indicates:",["What percentage of claims the company actually pays — higher is better","How expensive the premiums are","The company's profit margin","Number of hospitals in the network"],0,"A 95%+ settlement ratio means the company pays out 95 of every 100 claims. Always check before buying.","Check claim settlement ratio before buying health insurance. Above 95% is good.");
  add(2,"Fraud","If you accidentally share your OTP with a scammer:",["Immediately block your card, change passwords, and call your bank","Wait and watch for suspicious activity","Share it with more people for verification","Nothing — OTPs expire anyway"],0,"OTPs are valid for a few minutes — act immediately. Block card, change all passwords, alert bank.","Shared OTP? IMMEDIATELY: block card → change passwords → call bank.");
  add(2,"Fraud","Credit card skimming involves:",["A hidden device on ATMs or card machines that copies your card data","Normal card swiping at any machine","Online-only fraud","UPI-specific fraud"],0,"Skimmers are placed over legitimate card readers. Check for loose fittings on ATMs before inserting your card.","Wiggle the card slot at ATMs. If it's loose, don't use it — possible skimmer.");
  add(2,"Tax","Form 16 is issued by:",["Your employer, showing salary details and TDS deducted during the year","The government directly to citizens","Banks for interest income","SEBI for investments"],0,"Form 16 is your tax deduction certificate. You need it to file your income tax return.","Form 16: your employer's record of salary and tax deducted. Keep it for ITR filing.");

  // ── LAW ──
  add(3,"Rights","The Right to Privacy was declared a fundamental right in:",["2017, in the K.S. Puttaswamy vs Union of India case","2005","2010","1950"],0,"A 9-judge Supreme Court bench unanimously held privacy as intrinsic to life and liberty under Article 21.","Privacy = fundamental right since 2017. Landmark Puttaswamy judgment.");
  add(3,"Constitution","The basic structure doctrine means:",["Certain fundamental features of the Constitution cannot be altered even by Parliament","Only the Preamble is protected","Parliament can change anything","Only Article 1 is protected"],0,"Established in Kesavananda Bharati case (1973). Democracy, secularism, federalism are part of basic structure.","Basic structure: even Parliament cannot destroy core constitutional features.");
  add(3,"Consumer","The National Consumer Helpline number is:",["1800-11-4000 (toll-free)","100","112","1098"],0,"Call this number to file consumer complaints, get guidance on your rights, and seek redressal.","Consumer issue? Call 1800-11-4000 (toll-free). File complaints online at consumerhelpline.gov.in.");
  add(3,"Consumer","Misleading advertisements are punishable under:",["Consumer Protection Act 2019, with fines up to Rs 10 lakh","No law covers misleading ads","Only moral guidelines apply","Only international trade law"],0,"The CCPA (Central Consumer Protection Authority) can impose penalties and order corrective ads.","False ads = punishable offense. Report to CCPA or consumer helpline.");
  add(3,"Traffic","The penalty for drunk driving in India can include:",["Up to Rs 10,000 fine and/or imprisonment up to 6 months","Rs 500 fine only","Just a warning","Only license suspension for 1 week"],0,"Repeat offenses attract Rs 15,000 and/or 2 years imprisonment. Never drink and drive.","Drunk driving: up to Rs 10,000 fine + 6 months jail. NEVER worth the risk.");
  add(3,"Cyber Law","Sharing someone's private photos without consent is:",["A criminal offense under IT Act with imprisonment up to 3 years","Not covered by any law","Only morally wrong","Only a civil matter with no criminal penalty"],0,"Section 66E of IT Act criminalizes capturing or publishing private images. Victims can file FIR.","Non-consensual intimate image sharing: criminal offense. Up to 3 years jail.");
  add(3,"Governance","A suo motu case is one taken up by:",["A court on its own initiative, without any complaint being filed","The police only","Only the government","Only a citizen petition"],0,"Courts can take notice of issues from media reports or their own knowledge to protect public interest.","Suo motu: courts acting on their own. Important for public interest cases.");

  // ── DIGITAL ──
  add(4,"Privacy","Incognito/private browsing mode:",["Only prevents your browser from saving local history — ISP and websites still track you","Makes you completely anonymous online","Blocks all cookies permanently","Encrypts all your internet traffic like a VPN"],0,"Incognito hides history from other users of your device, but your ISP, employer, and websites still see you.","Incognito ≠ invisible. Your ISP and websites still see everything.");
  add(4,"Security","Ransomware attacks can be prevented by:",["Regularly backing up data, updating software, and not clicking suspicious links","Opening all email attachments to check them","Using only one password for everything","Never going online"],0,"Backups ensure you can recover without paying ransom. Keep software updated to patch vulnerabilities.","Best ransomware defense: regular backups + software updates + caution with links.");
  add(4,"AI","AI hallucinations refer to:",["AI generating confident but factually incorrect information","AI dreaming during processing","Computer overheating","AI refusing to answer questions"],0,"Large language models sometimes produce plausible-sounding but entirely fabricated facts.","AI can be confidently wrong. Always verify important AI-generated claims.");
  add(4,"AI","Deepfake technology is dangerous because it can:",["Create realistic fake videos making people appear to say things they never said","Only produce low-quality content","Only affect computers, not real life","Only be used by governments"],0,"Deepfakes threaten elections, relationships, and trust. Verify videos from unconfirmed sources.","Deepfakes: even realistic video can be completely fabricated. Verify sources.");
  add(4,"Social Media","The 'filter bubble' effect means:",["Algorithms only show content matching your existing views, limiting diverse perspectives","Using photo filters on images","Spam filtering in email","Social media censorship"],0,"Filter bubbles create echo chambers. Actively seek diverse viewpoints to break out of them.","Break your filter bubble: follow diverse sources, not just those you agree with.");

  // ── SCIENCE ──
  add(5,"Environment","A single plastic bag takes approximately how long to decompose?",["500 to 1,000 years","A few months","5 years","50 years"],0,"Plastic bags break into microplastics that contaminate soil and water for centuries. Use cloth bags.","Plastic bag: 500-1,000 years to decompose. Carry your own reusable bag.");
  add(5,"Environment","Microplastics are dangerous because:",["They enter food chains, water supplies, and have been found in human blood","They are expensive","They only affect marine life, not humans","They dissolve harmlessly in water"],0,"Microplastics have been found in drinking water, seafood, salt, and even human blood and placenta.","Microplastics: in our food, water, and blood. Reduce single-use plastic.");
  add(5,"Physics","Sound waves cannot travel through:",["A vacuum, because there are no particles to vibrate","Air","Water","Metal"],0,"Sound needs a medium (solid, liquid, or gas) to travel. Space is silent because it's a vacuum.","No sound in space. Sound needs particles — a vacuum has none.");
  add(5,"Physics","Static electricity is caused by:",["Transfer of electrons between objects through friction","Running water","Magnetic fields alone","Heat from the sun"],0,"Rubbing materials together transfers electrons, creating a charge imbalance that causes sparks.","Doorknob shock = static electricity from electron transfer. Friction causes it.");
  add(5,"Chemistry","Rust forms when iron reacts with:",["Oxygen and moisture in the air (oxidation)","Only pure water","Heat alone","Cold temperatures"],0,"Iron + oxygen + water = iron oxide (rust). Painting or galvanizing prevents this reaction.","Rust = iron + oxygen + water. Prevent it by painting or coating metal.");
  add(5,"Chemistry","Baking soda reacts with vinegar to produce:",["Carbon dioxide gas, causing fizzing","Oxygen gas","Hydrogen gas","No reaction occurs"],0,"This acid-base reaction produces CO2 gas, water, and sodium acetate. Popular in science experiments.","Baking soda + vinegar = CO2 fizz. Classic chemistry demonstration.");
  add(5,"Biology","The food chain always starts with:",["Producers (plants) that convert sunlight into energy","Carnivores at the top","Decomposers","Herbivores"],0,"Plants (producers) form the base. Energy flows: producers → herbivores → carnivores → decomposers.","Food chain base: plants. They convert sunlight into food for everything else.");

  // ── MATHS ──
  add(5,"Arithmetic","What is 17 x 13?",["221","231","211","201"],0,"17 x 13 = 17 x 10 + 17 x 3 = 170 + 51 = 221.","17 x 13 = 221. Break it: 170 + 51.");
  add(5,"Arithmetic","What is 25 x 25?",["625","525","725","600"],0,"25 squared = 625. Quick trick: for numbers ending in 5, multiply first digit by (first digit + 1), append 25.","25 x 25 = 625. Trick: 2×3=6, append 25 → 625.");
  add(5,"Arithmetic","What is 144 divided by 12?",["12","14","11","13"],0,"144 ÷ 12 = 12. Also, 12 x 12 = 144 (12 squared).","144 ÷ 12 = 12. Remember: 12² = 144.");
  add(5,"Percentages","What is 15% of 200?",["30","25","35","20"],0,"15% of 200 = 0.15 x 200 = 30. Quick: 10% is 20, 5% is 10, total 30.","15% of 200 = 30. Break it: 10%(20) + 5%(10) = 30.");
  add(5,"Percentages","A shirt costs Rs 600 with 20% discount. Sale price is:",["Rs 480","Rs 500","Rs 520","Rs 450"],0,"20% of 600 = 120. Sale price = 600 - 120 = 480.","20% off Rs 600 = Rs 480. Discount = Rs 120.");
  add(5,"Percentages","A student scores 72 out of 80. The percentage is:",["90%","85%","88%","92%"],0,"72/80 x 100 = 90%.","72 out of 80 = 90%. Quick: 72/8 = 9, so 90%.");
  add(5,"Geometry","The sum of angles in a triangle is always:",["180 degrees","360 degrees","90 degrees","270 degrees"],0,"This is a fundamental property of all triangles — the three interior angles always sum to 180°.","Triangle angles always sum to 180°. Quadrilateral = 360°.");
  add(5,"Geometry","The area of a rectangle 10cm x 5cm is:",["50 sq cm","55 sq cm","45 sq cm","100 sq cm"],0,"Area of rectangle = length × width = 10 × 5 = 50 sq cm.","Rectangle area = length × width.");
  add(5,"Geometry","If a right triangle has sides 3 and 4, the hypotenuse is:",["5","6","7","4.5"],0,"Pythagorean theorem: 3² + 4² = 9 + 16 = 25. √25 = 5.","3-4-5: the most famous right triangle. a² + b² = c².");
  add(5,"Algebra","If 2x + 3 = 15, then x equals:",["6","7","5","8"],0,"2x + 3 = 15 → 2x = 12 → x = 6.","Solve: isolate x. 2x = 15-3 = 12, x = 6.");
  add(5,"Numbers","The first five prime numbers are:",["2, 3, 5, 7, 11","1, 2, 3, 5, 7","1, 3, 5, 7, 9","2, 4, 6, 8, 10"],0,"A prime number has exactly two factors: 1 and itself. 1 is NOT prime. 2 is the only even prime.","Primes: 2, 3, 5, 7, 11... Remember: 1 is NOT prime.");
  add(5,"Numbers","Is 1 a prime number?",["No — 1 is neither prime nor composite","Yes, it's the smallest prime","Yes, all odd numbers are prime","It depends on context"],0,"Prime numbers must have exactly 2 factors. 1 has only one factor (itself), so it's not prime.","1 is NOT prime. A prime has exactly 2 factors: 1 and itself.");
  add(5,"Profit & Loss","Cost price Rs 200, selling price Rs 250. Profit percentage:",["25%","20%","30%","50%"],0,"Profit = 250-200 = 50. Profit% = (50/200) x 100 = 25%.","Profit% = (Profit/CP) × 100. Here: (50/200) × 100 = 25%.");
  add(5,"Simple Interest","SI on Rs 5,000 at 10% for 2 years:",["Rs 1,000","Rs 500","Rs 1,500","Rs 2,000"],0,"SI = P × R × T / 100 = 5000 × 10 × 2 / 100 = 1000.","SI formula: P × R × T / 100.");
  add(5,"Speed & Distance","A car travels 240 km in 4 hours. Speed:",["60 km/h","80 km/h","50 km/h","70 km/h"],0,"Speed = Distance/Time = 240/4 = 60 km/h.","Speed = Distance ÷ Time. 240 ÷ 4 = 60 km/h.");
  add(5,"Ratio","If Rs 1,200 is divided in ratio 2:3, the larger share is:",["Rs 720","Rs 480","Rs 600","Rs 800"],0,"Total parts = 5. Larger share = (3/5) × 1200 = 720.","Ratio 2:3 means 5 parts. Larger gets 3/5 of total.");
  add(5,"Averages","Average of 10, 20, 30, 40, 50 is:",["30","25","35","20"],0,"Sum = 150. Count = 5. Average = 150/5 = 30.","Average = Sum ÷ Count. 150 ÷ 5 = 30.");
  add(5,"Probability","Probability of getting heads on a fair coin:",["1/2","1/4","1/3","2/3"],0,"A fair coin has 2 equally likely outcomes. P(heads) = 1/2 = 50%.","Fair coin: 1/2 chance of heads. Probability = favorable/total outcomes.");
  add(5,"Probability","Probability of rolling a 6 on a fair die:",["1/6","1/3","1/2","1/4"],0,"A die has 6 equally likely faces. P(6) = 1/6 ≈ 16.7%.","Fair die: 1/6 chance for any specific number.");
  add(5,"Measurement","1 kilometer equals:",["1,000 meters","100 meters","10,000 meters","500 meters"],0,"Kilo means thousand. 1 km = 1,000 m.","Kilo = thousand. 1 km = 1,000 m. 1 kg = 1,000 g.");
  add(5,"Measurement","How many seconds in 1 hour?",["3,600","360","600","1,200"],0,"1 hour = 60 minutes × 60 seconds = 3,600 seconds.","1 hour = 3,600 seconds. (60 × 60).");
  add(5,"Patterns","Next in sequence: 2, 4, 8, 16, 32, ?",["64","48","36","128"],0,"Each number doubles. 32 × 2 = 64. This is a geometric progression with ratio 2.","Pattern: each number doubles. 2, 4, 8, 16, 32, 64...");
  add(5,"Patterns","Next in Fibonacci: 1, 1, 2, 3, 5, 8, 13, ?",["21","18","15","26"],0,"Each number is the sum of the two before it. 8 + 13 = 21.","Fibonacci: each number = sum of previous two. 8+13 = 21.");
  add(5,"Fractions","What is 3/4 as a percentage?",["75%","70%","80%","65%"],0,"3 ÷ 4 = 0.75 = 75%.","3/4 = 75%. Quick: divide numerator by denominator × 100.");
  add(5,"Fractions","What is 1/2 + 1/4?",["3/4","1/4","2/4","1/2"],0,"1/2 = 2/4. So 2/4 + 1/4 = 3/4.","Find common denominator. 1/2 = 2/4. Then 2/4 + 1/4 = 3/4.");
  add(5,"Mental Math","To find 25% of a number quickly:",["Divide by 4","Divide by 5","Divide by 2","Multiply by 4"],0,"25% = 1/4. So divide the number by 4. Example: 25% of 80 = 80/4 = 20.","25% = quarter. Just divide by 4. Quick and easy.");
  add(5,"Mental Math","A number is divisible by 3 if:",["The sum of its digits is divisible by 3","It ends in 3","It is odd","The last two digits are divisible by 3"],0,"Example: 123 → 1+2+3=6, which is divisible by 3, so 123 is divisible by 3.","Divisibility by 3: add all digits. If sum ÷ 3 = whole number, it works.");
  add(5,"Word Problems","A and B can do a job in 10 and 15 days respectively. Together:",["6 days","5 days","8 days","7 days"],0,"A's rate = 1/10, B's rate = 1/15. Combined = 1/10 + 1/15 = 5/30 = 1/6. Together: 6 days.","Combined work: add rates. 1/10 + 1/15 = 1/6 → 6 days.");
  add(5,"Word Problems","If 6 books cost Rs 540, the cost of 10 books:",["Rs 900","Rs 800","Rs 1,000","Rs 850"],0,"Cost per book = 540/6 = 90. 10 books = 90 × 10 = 900.","Unit price first: 540÷6=90 per book. 10 books = Rs 900.");
  add(5,"Practical Math","GST at 18% on Rs 10,000 means total price:",["Rs 11,800","Rs 11,000","Rs 12,000","Rs 10,800"],0,"GST = 18% of 10,000 = 1,800. Total = 10,000 + 1,800 = 11,800.","18% GST on Rs 10,000: pay Rs 11,800 total.");
  add(5,"Practical Math","If 1 USD = Rs 83, then 50 USD equals:",["Rs 4,150","Rs 4,000","Rs 4,500","Rs 4,250"],0,"50 × 83 = 4,150.","Currency conversion: multiply amount × exchange rate.");
  add(5,"Practical Math","If EMI is Rs 5,000/month for 3 years, total repayment:",["Rs 1,80,000","Rs 1,50,000","Rs 2,00,000","Rs 1,60,000"],0,"3 years = 36 months. 5,000 × 36 = 1,80,000.","EMI total = monthly amount × months. Rs 5,000 × 36 = Rs 1,80,000.");

  // ── GOVERNANCE ──
  add(10,"Governance","Question Hour in Parliament is:",["The first hour when MPs ask questions to ministers about government functioning","A quiz show","A private session","An informal discussion"],0,"Question Hour holds the government accountable. It happens at the start of each parliamentary sitting.","Question Hour: MPs question ministers. Key accountability mechanism.");
  add(10,"Governance","FSSAI regulates:",["Food safety and standards in India","Factory safety","Financial services","Foreign services"],0,"FSSAI sets food safety standards, issues licenses, and ensures food quality across India.","FSSAI: ensures your food is safe. Check for the FSSAI logo on packaged food.");
  add(10,"Governance","The Rajya Sabha can delay a Money Bill for:",["A maximum of 14 days","30 days","60 days","90 days"],0,"After 14 days, the Money Bill is deemed passed whether Rajya Sabha acts or not.","Money Bills: Lok Sabha is supreme. Rajya Sabha gets only 14 days.");
  add(10,"Governance","A no-confidence motion can be moved in:",["Lok Sabha only","Rajya Sabha only","Both houses","Any state assembly"],0,"If passed, the government must resign. Only Lok Sabha can move it since the PM is responsible to Lok Sabha.","No-confidence motion: Lok Sabha only. If passed, government falls.");
  add(10,"International","The WTO (World Trade Organization) is headquartered in:",["Geneva, Switzerland","New York, USA","Washington DC, USA","Brussels, Belgium"],0,"WTO deals with international trade rules. Not to be confused with UN (New York) or World Bank (Washington).","WTO: Geneva. UN: New York. World Bank: Washington. WHO: Geneva.");
  add(10,"International","The WHO (World Health Organization) is headquartered in:",["Geneva, Switzerland","New York, USA","London, UK","Paris, France"],0,"WHO coordinates international public health from its Geneva headquarters.","WHO: Geneva, Switzerland. The UN's global health agency.");

  // ── HISTORY ──
  add(7,"India","The first Governor-General of independent India was:",["Lord Mountbatten","Warren Hastings","Jawaharlal Nehru","Rajendra Prasad"],0,"Mountbatten served briefly as Governor-General after independence. C. Rajagopalachari was the last.","Mountbatten: first GG of independent India. Rajagopalachari: the last.");
  add(7,"India","The Pokhran-II nuclear tests (Operation Shakti) were conducted in:",["1998","1974","2000","1988"],0,"India conducted 5 nuclear tests at Pokhran on May 11 and 13, 1998, under PM Atal Bihari Vajpayee.","Pokhran-II: May 1998. Made India a declared nuclear weapons state.");
  add(7,"India","The LPG economic reforms began in India in:",["1991, under PM Narasimha Rao and FM Manmohan Singh","1985","1995","2000"],0,"The 1991 balance of payments crisis led to Liberalization, Privatization, and Globalization reforms.","1991 reforms transformed India's economy: LPG by Narasimha Rao & Manmohan Singh.");
  add(7,"India","Operation Flood (White Revolution) was led by:",["Verghese Kurien, making India the world's largest milk producer","M.S. Swaminathan","Homi Bhabha","Sam Pitroda"],0,"Kurien's cooperative model through Amul transformed India from milk-deficient to the world's top producer.","Verghese Kurien: father of India's White Revolution. Amul's visionary.");
  add(7,"World","Nelson Mandela was imprisoned for:",["27 years for fighting apartheid in South Africa","5 years","10 years","40 years"],0,"Mandela spent 27 years in prison, then became South Africa's first Black president in 1994.","Mandela: 27 years imprisoned, then president. Symbol of justice and resilience.");

  // ── LANGUAGE ──
  add(8,"Vocab","A 'euphemism' is:",["A mild or indirect word used in place of something harsh or blunt","An insult","A scientific term","A grammatical error"],0,"Example: 'passed away' instead of 'died.' Euphemisms soften uncomfortable truths.","Euphemism: softened language. 'Let go' instead of 'fired.'");
  add(8,"Vocab","'Perseverance' means:",["Continuing steadfastly despite difficulty or obstacles","Giving up quickly","Being lucky","Avoiding challenges"],0,"Perseverance is the quality that separates those who succeed from those who give up too early.","Perseverance = persistence through difficulty. A key trait for success.");
  add(8,"Communication","Effective feedback should be:",["Specific, timely, actionable, and focused on behavior rather than personality","Vague and general","Only positive","Only negative and harsh"],0,"Good feedback describes specific behavior, explains impact, and suggests alternatives.","Good feedback: specific + timely + actionable. Focus on behavior, not person.");

  // ── CRITICAL THINKING ──
  add(9,"Logic","The 'appeal to nature' fallacy assumes:",["Everything natural is automatically good and everything artificial is bad","Nature is sometimes useful","Science replaces nature","All medicine should be natural"],0,"Arsenic and snake venom are natural. Penicillin is artificial. Natural ≠ safe or good.","Natural ≠ good. Arsenic is natural. Vaccines are artificial. Judge by evidence.");
  add(9,"Logic","Circular reasoning means:",["Using the conclusion as evidence for itself — 'it's true because it's true'","Arguments that go in productive cycles","Multiple people agreeing","Evidence arranged in circles"],0,"Example: 'This book is accurate because it says so inside the book.' No independent evidence offered.","Circular reasoning: using the claim as its own proof. Spot it and challenge it.");
  add(9,"Bias","The anchoring effect in shopping means:",["The first price you see influences what you consider a good deal","Comparing exactly 3 prices always","Only buying on sale days","Tying yourself to one store"],0,"Retailers show high 'original' prices first so the 'sale' price seems like a bargain by comparison.","Anchoring: first price seen shapes perception. 'Was Rs 2000, now Rs 999!'");
  add(9,"Decision","Analysis paralysis can be overcome by:",["Setting a deadline for the decision and accepting that perfect info is rarely available","Gathering infinite data first","Avoiding all analysis entirely","Flipping a coin always"],0,"Good decisions made on time beat perfect decisions made too late. Set a deadline and commit.","Done is better than perfect. Set a decision deadline and commit.");
  add(9,"Ethics","The 'tragedy of the commons' describes how:",["Individuals acting in self-interest can deplete shared resources, harming everyone","Shared parks are always maintained","Public goods are unlimited","Individual interests always align with public good"],0,"Example: overfishing — each fisher maximizes catch, but the fish population collapses for everyone.","Tragedy of commons: self-interest + shared resources = everyone loses.");

  // ── MIXED AWARENESS ──
  add(11,"Awareness","India's national aquatic animal is the:",["Gangetic River Dolphin","Shark","Blue Whale","Sea Turtle"],0,"The Gangetic River Dolphin was declared India's national aquatic animal in 2009 to raise conservation awareness.","Gangetic Dolphin: India's national aquatic animal. Endangered — needs protection.");
  add(11,"Awareness","ISRO's Chandrayaan-3 successfully landed on the Moon in:",["August 2023, making India the 4th country to achieve a soft lunar landing","2019","2021","2020"],0,"Chandrayaan-3's Vikram lander touched down near the lunar south pole on August 23, 2023.","Chandrayaan-3: Aug 23, 2023. India = 4th country for Moon landing.");
  add(11,"Awareness","APJ Abdul Kalam is known as:",["The Missile Man of India","Father of the Nation","Iron Man of India","Nightingale of India"],0,"Kalam led India's missile development program and later served as the 11th President of India.","APJ Abdul Kalam: Missile Man + 11th President. People's President.");
  add(11,"Awareness","Zero as a mathematical concept was developed by:",["Indian mathematicians including Aryabhata and Brahmagupta","Greek mathematicians","Roman mathematicians","Chinese mathematicians"],0,"Brahmagupta (628 CE) defined rules for zero in arithmetic. India's gift to world mathematics.","Zero: India's greatest mathematical gift to the world. Brahmagupta, 628 CE.");
  add(11,"Awareness","The national flower of India is the:",["Lotus","Rose","Sunflower","Jasmine"],0,"The lotus symbolizes divinity, fertility, and purity in Indian culture. It blooms in muddy water — beauty from adversity.","Lotus: India's national flower. Symbol of purity rising from muddy waters.");
  add(11,"Awareness","The Nobel Peace Prize is awarded in:",["Oslo, Norway (while other Nobels are in Stockholm, Sweden)","Stockholm, Sweden","Geneva, Switzerland","New York, USA"],0,"Alfred Nobel specified that Peace Prize be awarded by a Norwegian committee. All others are Swedish.","Peace Prize: Oslo. All other Nobels: Stockholm. Nobel's specific wish.");
  // ═══ BATCH 1: 500 verified questions (cor=0 always) ═══

  // ─── HEALTH: 100 questions ───
  add(0,"Nutrition","Ragi (finger millet) is especially rich in:",["Calcium — among the highest of any cereal","Vitamin D","Sodium","Fat"],0,"Ragi has 344mg calcium per 100g, making it one of the best non-dairy calcium sources.","Ragi: exceptional calcium source for strong bones.");
  add(0,"Nutrition","Iron absorption is enhanced when consumed with:",["Vitamin C-rich foods like citrus fruits","Tea or coffee","Milk","Cold water"],0,"Vitamin C converts iron to a more absorbable form. Avoid tea/coffee with iron-rich meals.","Eat citrus with iron-rich food. Avoid tea/coffee at mealtimes.");
  add(0,"Nutrition","The Mediterranean diet emphasizes:",["Olive oil, fish, whole grains, fruits, and vegetables","Red meat and butter","Processed foods","Deep-fried snacks"],0,"Associated with lower heart disease and diabetes risk in multiple large studies.","Mediterranean diet: proven heart benefits over decades of research.");
  add(0,"Nutrition","Turmeric's active compound curcumin has:",["Anti-inflammatory and antioxidant properties","High caffeine content","Antibiotic properties replacing medicine","No health benefits"],0,"Curcumin reduces inflammation. Absorption improves significantly with black pepper (piperine).","Turmeric + black pepper = better curcumin absorption.");
  add(0,"Nutrition","Overnight soaking of pulses before cooking:",["Improves digestibility and reduces cooking time","Removes all protein","Has no effect","Makes them toxic"],0,"Soaking breaks down phytic acid and enzyme inhibitors, improving nutrient absorption.","Soak dals overnight: better digestion, more nutrients, faster cooking.");
  add(0,"Nutrition","Flaxseeds are an excellent vegetarian source of:",["Omega-3 fatty acids","Vitamin B12","Calcium","Vitamin D"],0,"Ground flaxseeds provide ALA omega-3. Also rich in fiber and lignans.","Flaxseeds: best plant-based omega-3 source. Grind them for absorption.");
  add(0,"Nutrition","The BRAT diet helps with:",["Recovery from diarrhea and stomach upset","Muscle building","Weight gain","Athletic performance"],0,"Bananas, Rice, Applesauce, Toast — bland foods that are easy on the stomach during illness.","BRAT diet: gentle on upset stomachs. Bananas, Rice, Applesauce, Toast.");
  add(0,"Nutrition","Green tea contains beneficial:",["Antioxidants called catechins","High sugar levels","Saturated fats","Artificial colors"],0,"EGCG catechins in green tea have anti-inflammatory and potential cancer-preventive properties.","Green tea: rich in catechins. 2-3 cups daily for antioxidant benefits.");
  add(0,"Nutrition","Jaggery retains more minerals than white sugar because:",["It undergoes less refining, preserving iron and potassium","It has more calories","It is artificially sweetened","It dissolves faster"],0,"Jaggery retains iron, magnesium, and potassium lost during sugar refining. Still use in moderation.","Jaggery > white sugar for minerals. But still limit total intake.");
  add(0,"Nutrition","Amla (Indian gooseberry) is one of the richest sources of:",["Vitamin C","Iron","Fat","Protein"],0,"One amla has 20x more Vitamin C than an orange. Also rich in antioxidants.","Amla: Vitamin C powerhouse. Eat raw, as juice, or as pickle.");
  add(0,"Nutrition","Coconut water is a natural source of:",["Electrolytes and potassium","Protein","Iron","Vitamin D"],0,"Great for rehydration after exercise or illness. Contains potassium, sodium, and magnesium.","Coconut water: nature's electrolyte drink. Better than most sports drinks.");
  add(0,"Nutrition","Whole grains are healthier than refined grains because:",["They retain fiber, vitamins, and minerals removed during refining","They taste better","They have more sugar","They cook faster"],0,"Refining removes the bran and germ — where most fiber, B vitamins, and minerals are stored.","Choose brown rice, whole wheat over white. Refining strips nutrients.");
  add(0,"Nutrition","Dark chocolate in moderation may benefit:",["Heart health due to flavonoids and antioxidants","Bone strength","Lung capacity","Dental health"],0,"70%+ cocoa dark chocolate contains flavonoids that improve blood flow and lower blood pressure.","Dark chocolate (70%+ cocoa): heart-healthy in moderation. 1-2 squares daily.");
  add(0,"Nutrition","The recommended daily fruit and vegetable intake is at least:",["5 servings (about 400g)","1 serving","10 servings","No specific recommendation"],0,"WHO recommends 400g minimum daily. Variety of colors ensures diverse nutrient intake.","Eat 5+ servings of fruits and vegetables daily. Aim for variety.");
  add(0,"Nutrition","Processed foods are generally less healthy because they contain:",["Excess salt, sugar, unhealthy fats, and artificial additives","Too many vitamins","Too much protein","Too much fiber"],0,"Ultra-processed foods are linked to obesity, heart disease, and cancer. Read labels carefully.","Check food labels: high sodium, sugar, or ingredient lists = ultra-processed.");
  add(0,"Nutrition","Quinoa is considered a superfood because:",["It is a complete protein with all essential amino acids","It has no calories","It replaces water","It cures diseases"],0,"Unlike most plant foods, quinoa provides all 9 essential amino acids. Also rich in fiber and iron.","Quinoa: rare plant-based complete protein. Great for vegetarians.");
  add(0,"Nutrition","Fermented foods like idli, dosa, kimchi are healthy because:",["Fermentation increases nutrient availability and adds beneficial bacteria","They are fried","They lose all nutrients","They have more sugar"],0,"Fermentation creates probiotics and breaks down anti-nutrients, making minerals more available.","Fermented foods = natural probiotics. Curd, idli, kimchi all count.");
  add(0,"Nutrition","Caffeine's recommended daily limit for adults is about:",["400mg (about 4 cups of coffee)","100mg","1000mg","No limit exists"],0,"Exceeding 400mg can cause anxiety, insomnia, and heart palpitations. Pregnant women should limit to 200mg.","Caffeine limit: 400mg/day (~4 cups). Less for pregnant women.");
  add(0,"Nutrition","Potassium-rich foods include:",["Bananas, potatoes, spinach, and oranges","White bread only","Candy","Soda"],0,"Potassium regulates heart rhythm, muscle function, and blood pressure. Most adults don't get enough.","Eat bananas, potatoes, spinach for potassium. Vital for heart health.");
  add(0,"Nutrition","Seeds like pumpkin and sunflower are rich in:",["Zinc, magnesium, healthy fats, and protein","Only water","Only carbs","Sodium"],0,"A handful of mixed seeds provides significant micronutrients. Great as a snack or salad topping.","Mixed seeds: nutrient-dense snack. Pumpkin seeds are especially zinc-rich.");

  add(0,"Diseases","Chikungunya is transmitted through:",["Aedes mosquito bites, same as dengue","Contaminated water","Person-to-person contact","Airborne droplets"],0,"Symptoms: severe joint pain and fever. Prevention: eliminate stagnant water where Aedes breeds.","Chikungunya: same Aedes mosquito as dengue. Eliminate stagnant water.");
  add(0,"Diseases","Pneumonia is an infection of the:",["Lungs, where air sacs fill with fluid or pus","Stomach","Kidneys","Skin"],0,"Can be caused by bacteria, viruses, or fungi. Symptoms: cough, fever, difficulty breathing.","Pneumonia: lung infection. Cough + fever + breathlessness = see doctor.");
  add(0,"Diseases","Appendicitis pain typically:",["Starts around the navel and moves to the lower right abdomen","Stays in the chest","Affects only the legs","Occurs only in the head"],0,"Lower right pain with fever and nausea may indicate appendicitis — requires immediate surgery.","Pain moving to lower right abdomen = possible appendicitis. ER immediately.");
  add(0,"Diseases","PCOS affects:",["Women of reproductive age, causing hormonal imbalance","Only men","Only children","Only elderly women"],0,"Polycystic Ovary Syndrome affects 1 in 10 women. Causes irregular periods, acne, weight gain.","PCOS: 1 in 10 women. Treatable with lifestyle changes and medication.");
  add(0,"Diseases","Rabies can be prevented after a dog bite by:",["Washing wound with soap and water for 15 minutes and getting vaccinated immediately","Applying turmeric paste only","Ignoring it if the dog looked healthy","Tying a cloth around the bite"],0,"Rabies is nearly 100% fatal once symptoms appear. Post-exposure vaccination saves lives.","Dog bite: wash with soap 15 min → hospital → anti-rabies vaccine. Always.");
  add(0,"Diseases","The incubation period of dengue is typically:",["4-10 days after a mosquito bite","1 day","1 month","6 months"],0,"Symptoms appear 4-10 days after bite: high fever, severe headache, pain behind eyes, joint pain.","Dengue symptoms: 4-10 days after bite. High fever + body pain = get tested.");
  add(0,"Diseases","Kidney stones are most commonly prevented by:",["Drinking adequate water daily","Eating more salt","Avoiding all calcium","Skipping meals"],0,"Dehydration concentrates urine, allowing crystals to form. Drink 2-3 liters of water daily.","Kidney stones prevention: drink plenty of water. Simple and effective.");
  add(0,"Diseases","Gastritis is inflammation of the:",["Stomach lining","Lungs","Liver","Brain"],0,"Caused by H. pylori bacteria, excess alcohol, NSAIDs, or stress. Symptoms: burning stomach pain.","Gastritis: stomach lining inflammation. Avoid spicy food, alcohol, painkillers.");
  add(0,"Diseases","Heat exhaustion, if untreated, can progress to:",["Heatstroke, which is a life-threatening emergency","Just tiredness","A cold","Hunger"],0,"Heatstroke: body temp above 40°C, confusion, loss of consciousness. Call emergency immediately.","Heat exhaustion → heatstroke if ignored. Move to shade, hydrate, cool down.");
  add(0,"Diseases","Conjunctivitis (pink eye) spreads mainly through:",["Direct contact with infected secretions or contaminated surfaces","Food only","Blood transfusion","Insect bites"],0,"Highly contagious. Wash hands frequently, don't touch eyes, don't share towels.","Pink eye: DON'T touch eyes, DON'T share towels, DO wash hands constantly.");

  add(0,"Body","The strongest bone in the human body is:",["The femur (thighbone)","The skull","A rib","The spine"],0,"The femur is the longest, strongest bone — it supports your entire body weight.","Femur: strongest bone. Can withstand forces of 1,700-1,800 pounds.");
  add(0,"Body","The funny bone sensation comes from hitting:",["The ulnar nerve at the elbow, not an actual bone","The humerus bone directly","Elbow cartilage","The radius bone"],0,"The ulnar nerve runs close to the skin at the elbow with minimal protection.","Funny bone = ulnar nerve. Not a bone at all — just an unprotected nerve.");
  add(0,"Body","Taste buds detect five basic tastes:",["Sweet, sour, salty, bitter, and umami (savory)","Only sweet and sour","Sweet, sour, salty, and spicy","Only sweet, salty, bitter"],0,"Umami was identified as the 5th taste in 1908. Found in tomatoes, cheese, and soy sauce.","5 tastes: sweet, sour, salty, bitter, umami. Spicy is pain, not a taste.");
  add(0,"Body","Human hair grows approximately:",["About 15 cm (6 inches) per year","1 mm per year","1 meter per year","It does not grow after age 20"],0,"Hair grows about 1.25 cm per month. Scalp hair has a growth phase of 2-7 years.","Hair grows ~1.25 cm/month. Healthy diet and care promote growth.");
  add(0,"Body","The appendix may serve as:",["A reservoir for beneficial gut bacteria","A second stomach","An extra kidney","A hormone producer"],0,"Once thought useless, research shows it may help recolonize the gut with good bacteria after illness.","The appendix isn't useless — it stores good bacteria for gut recovery.");
  add(0,"Body","Goosebumps are caused by:",["Tiny muscles at hair follicle bases contracting","Allergic reactions","Skin disease","Cold directly freezing skin"],0,"An evolutionary leftover from when our ancestors had more body hair — it would fluff up for warmth.","Goosebumps: evolutionary relic. Tiny muscles contract at hair roots.");
  add(0,"Body","The human body replaces most of its cells every:",["7-10 years on average","1 day","1 week","Never — cells last a lifetime"],0,"Different cells replace at different rates: stomach lining in days, bones in ~10 years, some neurons never.","Your body is constantly rebuilding. Most cells replaced within 7-10 years.");
  add(0,"Body","The hardest substance in the human body is:",["Tooth enamel","Bone","Fingernails","Cartilage"],0,"Enamel is harder than steel but more brittle. It cannot regenerate once damaged.","Tooth enamel: harder than bone or steel. Protect it — it can't regrow.");
  add(0,"Body","Red blood cells live for approximately:",["120 days before being replaced","1 day","1 year","Forever"],0,"Your bone marrow produces about 2 million new red blood cells every second to replace old ones.","Red blood cells: 120-day lifespan. Bone marrow makes 2 million per second.");
  add(0,"Body","The human brain uses approximately:",["20% of the body's total energy despite being only 2% of body weight","5% of energy","50% of energy","1% of energy"],0,"The brain is incredibly energy-hungry, consuming glucose constantly even during sleep.","Brain: 2% of body weight, 20% of energy. Feed it well.");

  add(0,"Mental","The 5-4-3-2-1 grounding technique for anxiety involves:",["Noticing 5 things you see, 4 you touch, 3 you hear, 2 you smell, 1 you taste","Counting to 5 repeatedly","Taking 5 deep breaths","Listing 5 worries"],0,"This sensory technique breaks the anxiety cycle by anchoring you to the present moment.","Anxiety grounding: see 5, touch 4, hear 3, smell 2, taste 1.");
  add(0,"Mental","Burnout is characterized by:",["Emotional exhaustion, cynicism, and reduced effectiveness at work","High energy and enthusiasm","Only physical tiredness","Being lazy"],0,"WHO recognizes burnout as an occupational phenomenon. It requires rest and boundary-setting.","Burnout is real and medical. Rest is not laziness — it's recovery.");
  add(0,"Mental","Social media overuse has been linked to:",["Increased anxiety, depression, and poor body image in teenagers","Only better social connections","Improved academic performance","Better sleep"],0,"Studies show correlation between heavy social media use and mental health issues, especially in teens.","Monitor teen screen time. Social media affects self-esteem and sleep.");
  add(0,"Mental","Seasonal Affective Disorder (SAD) typically worsens in:",["Winter, when there is less sunlight","Summer","Spring","Autumn only"],0,"Reduced sunlight disrupts serotonin and melatonin production. Light therapy can help.","SAD: winter depression from less sunlight. Light therapy boxes can help.");
  add(0,"Mental","Journaling can help with:",["Processing emotions, reducing stress, and improving mental clarity","Only creative writing skills","Physical fitness","Weight loss"],0,"Writing about thoughts and feelings helps process experiences and identify patterns.","Try journaling: write freely for 10 minutes daily. Reduces stress measurably.");
  add(0,"Mental","The stigma around mental health in India:",["Prevents many people from seeking help despite conditions being treatable","Does not exist","Only affects rural areas","Is declining rapidly with no remaining barriers"],0,"Mental health conditions are medical, not character flaws. Professional help works.","Mental health = health. Seeking help is strength, not weakness.");

  add(0,"Vaccines","The OPV (Oral Polio Vaccine) is given to children:",["As oral drops, making mass immunization campaigns easier","Only as an injection","Only to adults","Only during hospitalization"],0,"India used mass OPV campaigns (pulse polio) to achieve polio-free status in 2014.","OPV: oral drops. India's pulse polio campaign eradicated polio by 2014.");
  add(0,"Vaccines","The Hepatitis B vaccine is given:",["At birth as part of India's Universal Immunization Programme","Only to adults over 40","Only when traveling abroad","Only after infection"],0,"Hepatitis B can cause chronic liver disease and cancer. Birth-dose vaccination prevents transmission.","Hep B vaccine at birth: prevents chronic liver disease. Part of routine immunization.");
  add(0,"Vaccines","Vaccines do NOT cause autism — this myth originated from:",["A fraudulent 1998 study that was retracted and the author lost his medical license","Verified scientific research","WHO recommendations","Multiple replicated studies"],0,"Andrew Wakefield's study was proven fraudulent. Dozens of studies with millions of children found no link.","Vaccines don't cause autism. The original claim was proven fraud.");
  add(0,"Vaccines","Flu vaccines are recommended:",["Annually, because influenza viruses mutate every year","Once in a lifetime","Only during pandemics","Never for healthy people"],0,"Flu strains change each year. Annual vaccination reduces illness severity and hospitalization.","Get a flu shot yearly. The virus changes — last year's vaccine won't fully protect.");

  add(0,"First Aid","The RICE method for sprains stands for:",["Rest, Ice, Compression, Elevation","Run, Ice, Compress, Eat","Relax, Immerse, Cold, Exercise","Rub, Ice, Cover, Elevate"],0,"Start RICE immediately after a sprain. Ice for 20 min on, 20 min off.","Sprain → RICE immediately. Ice 20 min on, 20 min off. Elevate above heart.");
  add(0,"First Aid","A knocked-out permanent tooth should be stored in:",["Milk or the person's own saliva until reaching a dentist","Warm water","Dry tissue paper","Antiseptic liquid"],0,"Milk's pH and osmolality keep tooth root cells alive for reimplantation. Time is critical.","Knocked tooth → milk → dentist within 30 minutes for best chance.");
  add(0,"First Aid","If someone is having an asthma attack without an inhaler:",["Help them sit upright, stay calm, and call emergency services","Make them lie flat on their back","Have them breathe into a paper bag","Make them run to open airways"],0,"Upright position maximizes airway opening. Stay calm — panic worsens bronchospasm.","Asthma attack: sit upright, calm breathing, call 112 if no inhaler available.");
  add(0,"First Aid","If someone swallows poison, you should:",["Call poison control or 112 immediately — do NOT induce vomiting unless told to","Make them vomit right away","Give them milk to neutralize","Wait and see what happens"],0,"Some poisons cause more damage coming back up. Professional guidance is essential.","Poison: DON'T make them vomit. Call poison helpline or 112 for guidance.");
  add(0,"First Aid","Heatstroke symptoms include:",["Body temperature above 40°C, confusion, hot dry skin, loss of consciousness","Mild sweating and thirst","Slight headache only","Cold clammy skin"],0,"Heatstroke is a medical emergency. Move to shade, cool with water/ice, call 112 immediately.","Body temp above 40°C + confusion = heatstroke. Emergency. Cool and call 112.");

  // ─── SAFETY: 80 questions ───
  add(1,"Road","The most common distraction causing driving accidents is:",["Using a mobile phone","Adjusting mirrors","Changing radio stations","Talking to passengers calmly"],0,"Texting while driving makes a crash 23 times more likely. Even hands-free calls reduce attention.","Phone while driving: 23x crash risk. It can wait.");
  add(1,"Road","Hydroplaning occurs when:",["Water builds between tires and road causing loss of traction","Tires overheat","Brakes fail due to heat","Engine overheats"],0,"Reduce speed on wet roads. If hydroplaning, ease off gas gently — don't brake hard.","Wet road: slow down. Hydroplaning starts around 55 km/h.");
  add(1,"Road","If your car starts to skid on a wet road:",["Ease off the accelerator and steer where you want to go","Brake hard immediately","Accelerate to power through","Sharply turn the wheel opposite"],0,"Gentle corrections let tires regain traction. Hard braking worsens the skid.","Skidding: ease off gas, steer toward safety. No sudden moves.");
  add(1,"Road","Child car seats reduce fatal injury in toddlers by about:",["71%","10%","30%","50%"],0,"Properly installed child seats are one of the most effective vehicle safety devices for children.","Child car seat: 71% less fatal injuries. Always use one, properly installed.");
  add(1,"Road","In foggy conditions, you should use:",["Low beam headlights and fog lights","High beams for maximum visibility","No lights at all","Only hazard lights"],0,"High beams reflect off fog particles and actually reduce your visibility.","Fog: LOW beams + fog lights. High beams make it worse.");
  add(1,"Road","The three-second rule for following distance means:",["Keep at least 3 seconds of travel time between you and the car ahead","Speed limit is 3 seconds away","Stop for 3 seconds at every junction","Honk 3 times before passing"],0,"Pick a landmark. When the car ahead passes it, count 3 seconds. Increase in rain or at night.","Following distance: pick a mark, count '1-one-thousand, 2-one-thousand, 3-one-thousand.'");
  add(1,"Road","Drowsy driving is as dangerous as:",["Drunk driving — fatigue impairs reaction time and judgment similarly","Driving in light rain","Normal driving at night","Driving in traffic"],0,"Being awake 18+ hours impairs driving like a blood alcohol level of 0.05%.","Drowsy = drunk driving. Pull over and rest if tired. Coffee is temporary.");
  add(1,"Road","Worn-out tire treads are dangerous because:",["Braking distance increases dramatically, especially on wet roads","Only fuel consumption rises","The car looks old","Only comfort is affected"],0,"Below 1.6mm tread depth, tires cannot channel water effectively, causing aquaplaning.","Check tire tread: coin test. Replace below 1.6mm. Your safety depends on it.");
  add(1,"Road","If your brakes fail while driving:",["Pump brakes, downshift gradually, use parking brake gently, steer to safety","Jump out of the car","Accelerate to find help","Turn off the engine immediately"],0,"Pumping may restore hydraulic pressure. Downshifting uses engine braking to slow down.","Brake failure: pump brakes → downshift → parking brake gently → steer to safety.");
  add(1,"Road","Pedestrians should walk on which side when there is no footpath:",["The right side, facing oncoming traffic","The left side","The middle of the road","Either side"],0,"Facing traffic lets you see approaching vehicles and react to danger.","Walk facing traffic (right side in India). See danger coming.");

  add(1,"Cyber","If you receive a bank email asking to verify your account urgently:",["Do not click any links — contact your bank through official channels","Click the link immediately","Reply with your details","Forward it to friends"],0,"Banks never send urgent verification emails with links. Always use the official app or phone number.","Urgent bank email with links = phishing. Always contact bank directly.");
  add(1,"Cyber","Public WiFi networks are risky because:",["Hackers can intercept data on unsecured networks","They are slow","They use too much battery","The signal is weak"],0,"Use a VPN on public WiFi. Never access banking or enter passwords without encryption.","Public WiFi: use VPN. Never do banking. Hackers can see your data.");
  add(1,"Cyber","Before installing any app, check:",["Reviews, permissions, developer reputation, and download count","Only the app icon","Nothing — all apps are safe","Only the file size"],0,"A flashlight app asking for contact access is suspicious. Match permissions to function.","App wants contacts/camera/location? Ask: does it NEED this to work?");
  add(1,"Cyber","A money mule scheme involves:",["Unknowingly letting your bank account be used for laundering stolen money","A type of investment","Saving money wisely","A cryptocurrency strategy"],0,"Criminals recruit people to transfer stolen funds. You become criminally liable.","Never let strangers use your bank account. 'Easy money' transfer jobs = mule scheme.");
  add(1,"Cyber","If your social media account is hacked, first:",["Change password immediately and enable two-factor authentication","Create a new account","Post about it on the hacked account","Wait and see"],0,"Quick password change prevents further damage. Enable 2FA on all important accounts.","Hacked? Change password NOW → enable 2FA → check connected apps → alert contacts.");
  add(1,"Cyber","When shopping online, a secure page should show:",["https:// with a lock icon in the browser bar","Only http://","No specific indicators","A green background"],0,"HTTPS encrypts data, but verify the site is legitimate too — scam sites use HTTPS.","https + lock icon = encrypted. But also verify the website is genuine.");
  add(1,"Cyber","OTP (One Time Password) should:",["Never be shared with anyone — it is your personal security key","Be shared with bank callers when asked","Be written in your wallet","Be same as your ATM PIN"],0,"No bank, company, or government official will ever legitimately ask for your OTP.","NEVER share OTP. Not with bank staff, not with delivery people, not with anyone.");
  add(1,"Cyber","Clicking unsubscribe in suspicious spam email can:",["Confirm your email is active and lead to more spam or phishing","Always safely remove you","Have no effect","Is legally required to work"],0,"Scammers use fake unsubscribe links to verify active emails or redirect to phishing sites.","Suspicious spam: DON'T click unsubscribe. Just mark as spam and delete.");
  add(1,"Cyber","Ransomware can be prevented by:",["Regular backups, updated software, and not clicking suspicious links","Opening all attachments to check them","Using one password everywhere","Never going online"],0,"If you have recent backups, you can restore files without paying ransom.","Ransomware defense: backup regularly + update software + don't click suspicious links.");
  add(1,"Cyber","The safest way to dispose of an old phone is:",["Factory reset, remove SIM and SD card, then take to e-waste center","Throw in regular trash","Just remove the SIM and sell","Smash it with a hammer"],0,"Factory reset removes personal data. Removing SIM/SD prevents contact and file access.","Old phone: factory reset → remove SIM → remove SD card → e-waste.");

  add(1,"Fire","A kitchen oil fire should NEVER be put out with:",["Water — it causes explosive splattering","A fire blanket","A metal lid over the pan","Turning off the heat"],0,"Water vaporizes instantly in hot oil, creating a steam explosion that spreads burning oil.","Oil fire: NEVER water. Use lid, fire blanket, or turn off heat.");
  add(1,"Fire","The leading cause of fire deaths is:",["Smoke inhalation, not burns","Direct burns from flames","Falling debris","Structural collapse"],0,"Toxic smoke kills faster than flames. This is why crawling low and covering mouth matters.","Smoke kills faster than fire. Stay LOW — clean air is near the floor.");
  add(1,"Fire","Before opening a door during a fire:",["Feel the door with the back of your hand for heat","Kick it open immediately","Look through the keyhole","Open it as fast as possible"],0,"Hot door means fire on the other side. Use the back of your hand so you don't burn your palm.","Hot door = fire behind it. Find another exit. Back of hand to test.");
  add(1,"Fire","A home fire escape plan should include:",["At least two escape routes from every room and an outdoor meeting point","Only the front door exit","Only relevant for apartments","Just one exit route"],0,"Practice the plan twice a year. Ensure everyone knows the meeting point outside.","Two exits per room + meeting point outside. Practice twice yearly.");
  add(1,"Fire","Smoke detectors should be tested:",["Every month by pressing the test button","Once a year","Only when installed","They never need testing"],0,"Also replace batteries at least yearly. Smoke detectors cut fire death risk by 50%.","Test smoke detectors monthly. Replace batteries yearly. They save lives.");

  add(1,"Scam","A digital arrest scam involves callers claiming to be:",["Police threatening arrest unless you pay immediately","Bank managers offering loans","Insurance agents","Telecom companies"],0,"No real law enforcement demands money over phone. Legal processes require court orders.","No police/CBI officer demands money on phone. 'Digital arrest' = SCAM. Hang up.");
  add(1,"Scam","QR code payment scams work because:",["Scanning a QR code sends money FROM you, never TO you","QR codes are always safe","QR codes cannot transfer money","They only work on certain phones"],0,"Scammers say 'scan to receive money' but scanning actually debits your account.","QR codes = for PAYING only. Never scan to 'receive' money. Always a scam.");
  add(1,"Scam","Investment scams typically promise:",["Guaranteed high returns with zero risk","Normal market returns","Low returns with safety","No returns at all"],0,"No legitimate investment guarantees high returns without risk. If too good to be true, it is.","'Guaranteed 50% returns, zero risk!' = scam. Always. Every time.");
  add(1,"Scam","Work-from-home job scams usually require:",["You to pay money upfront for training or materials","No payment at all","Only an interview","Submitting a resume"],0,"Legitimate employers never charge employees to work. Upfront fees = scam.","Real jobs never ask you to PAY money to get hired.");
  add(1,"Scam","Romance scams on dating apps typically involve:",["Building emotional connection online, then asking for money","Meeting in person immediately","Sharing verified documents","Video calling regularly"],0,"Scammers invest weeks building trust before requesting money for 'emergencies.'","Online romance + never meeting + money requests = scam. Every time.");

  add(1,"Disaster","An emergency kit should have supplies for:",["At least 72 hours (3 days)","12 hours","1 week minimum","1 month"],0,"Water (3L/person/day), food, meds, flashlight, radio, first aid kit, documents.","Emergency kit: 3 days of water, food, meds, flashlight, documents. Prepare now.");
  add(1,"Disaster","The eye of a cyclone is:",["A deceptively calm area surrounded by the most violent winds","The most dangerous part with highest winds","The weakest part","Where the cyclone ends"],0,"Don't go outside during the eye — the worst winds come immediately after.","Cyclone eye: calm but temporary. Stay sheltered — worst winds follow.");
  add(1,"Disaster","During a flood, you should never:",["Drive or walk through floodwater","Move to higher ground","Store clean water","Turn off electricity"],0,"Just 6 inches of moving water knocks you down. 2 feet floats a car.","NEVER enter floodwater. Turn around, don't drown. 6 inches can kill.");
  add(1,"Disaster","After an earthquake, you should:",["Check for gas leaks, avoid damaged buildings, and expect aftershocks","Immediately re-enter your building","Ignore any cracks in walls","Assume it's completely over"],0,"Aftershocks can be strong enough to collapse weakened structures. Stay cautious for days.","Post-quake: check gas leaks, avoid damaged buildings, expect aftershocks for days.");

  // ─── MONEY: 80 questions ───
  add(2,"Banking","NEFT transfers are processed:",["In batches at regular intervals throughout the day","Instantly like IMPS","Once a week","Once a month"],0,"NEFT settles in half-hourly batches. For instant transfers use IMPS or UPI.","NEFT: batch. IMPS/UPI: instant. RTGS: real-time for Rs 2L+.");
  add(2,"Banking","A demand draft cannot bounce because:",["It is prepaid by the sender through their bank","It is the same as a cheque","It has no security features","It is always digital"],0,"Unlike personal cheques, DDs are prepaid — the bank guarantees payment.","DD = prepaid = guaranteed. Cheque = promise = can bounce.");
  add(2,"Banking","DICGC insures bank deposits up to:",["Rs 5 lakh per depositor per bank","Rs 1 lakh","Rs 10 lakh","Unlimited amount"],0,"If your bank fails, you're covered up to Rs 5 lakh including principal and interest.","Your deposits are insured up to Rs 5 lakh per bank. Spread large amounts.");
  add(2,"Banking","A savings account typically earns:",["3-4% annual interest, often below inflation","10-12% interest","0% interest","20% interest"],0,"At 3-4% interest with 6% inflation, your money actually loses purchasing power in savings accounts.","Savings account: safe but losing to inflation. Invest surplus for real growth.");
  add(2,"Banking","KYC (Know Your Customer) is required for:",["All banking services and financial transactions","Only business accounts","Only international transfers","Only gold purchases"],0,"KYC prevents fraud and money laundering. Required for bank accounts, investments, insurance.","KYC: mandatory for all financial services. Keep documents updated.");
  add(2,"Banking","A cheque that bounces is:",["A criminal offense under Section 138 of Negotiable Instruments Act","Just inconvenient","Only the bank's problem","Free of any penalty"],0,"Bounced cheques can lead to fines and imprisonment. Always ensure sufficient balance.","Bounced cheque = criminal offense. Fine + possible jail time. Maintain balance.");

  add(2,"Investment","ELSS mutual funds have a lock-in of:",["3 years — shortest among 80C tax-saving options","1 year","5 years","15 years"],0,"ELSS offers tax savings under 80C with equity growth potential. PPF locks for 15 years in comparison.","ELSS: 3-year lock-in + equity returns + 80C tax saving. Best combo.");
  add(2,"Investment","SIP helps because:",["You buy more units when prices are low and fewer when high","You always buy at the lowest price","It guarantees profits","It eliminates all risk"],0,"Rupee cost averaging smooths out market volatility over time. Consistency beats timing.","SIP: don't time the market, be consistent. More units when cheap.");
  add(2,"Investment","A Demat account is needed for:",["Holding stocks and securities electronically","Opening a savings account","Getting a home loan","Filing tax returns"],0,"Dematerialized accounts replaced physical share certificates. Required for stock trading.","Demat: your electronic locker for stocks. Open one to start investing.");
  add(2,"Investment","Mutual fund NAV represents:",["Per-unit market value of the fund, calculated daily","Total fund profit","Entry fee","Manager's salary"],0,"NAV = (Total Assets - Liabilities) / Total Units. It changes daily with market movements.","NAV: the 'price' of one unit of a mutual fund. Changes daily.");
  add(2,"Investment","Blue chip stocks belong to:",["Large, well-established, financially stable companies","New startups only","Only tech companies","Government bonds"],0,"Examples: Reliance, TCS, HDFC Bank. Lower risk than small-caps but not risk-free.","Blue chips: safe-ish but not guaranteed. Reliance, TCS, Infosys = blue chips.");
  add(2,"Investment","The difference between equity and debt investments:",["Equity = ownership with higher risk/return; Debt = lending with lower risk/fixed return","They are identical","Equity is always safer","Debt always gives higher returns"],0,"Stocks (equity) = you own a piece. Bonds/FDs (debt) = you lend money.","Equity = own + risk. Debt = lend + stability. Balance both in portfolio.");
  add(2,"Investment","Index funds are attractive because:",["They track market indices with very low management fees","They guarantee profits","They only hold one stock","They are risk-free"],0,"Low-cost index funds often outperform actively managed funds over long periods.","Index funds: low fees + market returns. Warren Buffett recommends them.");
  add(2,"Investment","NPS (National Pension System) is open to:",["All Indian citizens aged 18-70","Only government employees","Only private sector","Only self-employed"],0,"NPS offers additional tax benefits of Rs 50,000 under Section 80CCD(1B), beyond 80C.","NPS: extra Rs 50K tax deduction beyond 80C. Open to everyone 18-70.");

  add(2,"Insurance","Health insurance claim settlement ratio shows:",["What percentage of claims the company pays — higher is better","Premium cost","Company profit","Hospital count"],0,"Check this before buying. Above 95% is good. Below 90% is a red flag.","Claim settlement ratio: THE most important metric when buying health insurance.");
  add(2,"Insurance","Health insurance waiting period for pre-existing diseases is:",["Typically 2-4 years depending on the policy","No waiting period","1 week","10 years"],0,"Buy health insurance early — when you're young and healthy, you avoid waiting period issues.","Buy health insurance young. Pre-existing disease waiting period = 2-4 years.");
  add(2,"Insurance","Term life insurance is the cheapest because:",["It provides only death benefit with no maturity payout","It combines investment and insurance","It covers only accidents","It has very short coverage"],0,"Pure protection at lowest cost. Rs 1 crore cover costs Rs 10,000-15,000/year for a 30-year-old.","Term insurance: maximum cover, minimum cost. Every earning adult needs it.");

  add(2,"Tax","Under Section 80C, maximum tax deduction is:",["Rs 1.5 lakh per year","Rs 50,000","Rs 1 lakh","Rs 2 lakh"],0,"Eligible: PPF, ELSS, NPS, life insurance premium, EPF, NSC, tuition fees.","80C limit: Rs 1.5 lakh. Use PPF + ELSS + EPF to maximize.");
  add(2,"Tax","GST was implemented in India on:",["July 1, 2017","January 1, 2015","April 1, 2018","March 1, 2016"],0,"GST replaced 15+ indirect taxes with one unified system — 'One Nation, One Tax.'","GST: July 1, 2017. One Nation, One Tax. 4 slabs: 5%, 12%, 18%, 28%.");
  add(2,"Tax","Form 16 is issued by:",["Your employer, showing salary and TDS details","The government directly","Banks for interest","SEBI for investments"],0,"Form 16 is your TDS certificate — essential for filing income tax returns.","Form 16: salary + TDS certificate from employer. Keep it for ITR filing.");
  add(2,"Tax","Income tax returns should be filed by:",["July 31 of the assessment year","March 31","December 31","Any time within 5 years"],0,"Late filing attracts penalties of Rs 1,000-10,000 and interest on unpaid tax.","File ITR by July 31. Late = penalty + interest. E-file on incometax.gov.in.");
  add(2,"Tax","PAN card is mandatory for:",["Financial transactions above specified limits and tax filing","Only business owners","Only NRIs","Only government employees"],0,"PAN is linked to all financial activities: bank accounts, property, investments, tax returns.","Every earning adult needs a PAN card. Apply at NSDL or UTIITSL.");

  add(2,"Fraud","If you accidentally shared your OTP with a scammer:",["Immediately block your card, change passwords, and call your bank","Wait and see","Share with more people","Nothing — OTPs expire anyway"],0,"OTPs are valid for minutes. Act immediately — every second counts.","Shared OTP? Act in SECONDS: block card → change all passwords → call bank.");
  add(2,"Fraud","Credit card skimming uses:",["Hidden devices on ATMs that copy your card data","Normal card swiping","Online-only methods","UPI exclusively"],0,"Check for loose card slots or hidden cameras at ATMs. Cover keypad when entering PIN.","ATM safety: wiggle card slot (loose = skimmer), cover PIN pad, use bank ATMs.");
  add(2,"Fraud","Fake loan apps often:",["Ask access to contacts and photos, then harass you for payment","Follow RBI regulations","Charge standard interest","Require proper documentation"],0,"These apps charge 100%+ interest, access your phone data, and blackmail defaulters.","Avoid unknown loan apps. Verify RBI registration. They access and misuse your data.");
  add(2,"Fraud","UPI 'wrong transfer' scam works by:",["Sending money then requesting return — original gets reversed, you lose your money","Genuine accident every time","Only affecting old phones","Being impossible on UPI"],0,"The 'accidental' payment may be from a stolen account. Your 'return' goes to the scammer.","UPI 'wrong transfer'? NEVER send money back. Contact your bank to verify first.");
  add(2,"Saving","The power of compound interest is best shown by:",["Starting to invest early gives decades more compounding time","Investing only when markets are high","Waiting until age 50","Keeping money under the mattress"],0,"Rs 5,000/month from age 25 at 12% = Rs 3.25 crore at 60. Starting at 35 = only Rs 1 crore.","Start at 25 vs 35: 3x more wealth. Time is compound interest's best friend.");

  // ─── LAW: 60 questions ───
  add(3,"Rights","Right to Privacy was declared fundamental in:",["2017 in the K.S. Puttaswamy case","2005","2010","1950"],0,"A 9-judge bench unanimously held privacy as intrinsic to life and liberty under Article 21.","Privacy = fundamental right since 2017. Covers data, body, choice.");
  add(3,"Rights","Under Indian law, a juvenile is anyone below:",["18 years","16 years","14 years","21 years"],0,"The Juvenile Justice Act treats offenders under 18 through a rehabilitation-focused system.","Juvenile = under 18. Separate justice system focused on reform.");
  add(3,"Rights","Every arrested person has the right to:",["Be informed of arrest grounds and consult a lawyer","No rights at all","Only one phone call","See a judge only after a week"],0,"Article 22 guarantees these rights. You can also demand to be produced before a magistrate within 24 hours.","Arrested? Know your rights: told why, lawyer access, magistrate within 24 hours.");
  add(3,"Rights","Freedom of speech in India has restrictions for:",["National security, public order, decency, and defamation","No restrictions exist","Only during emergencies","Only for media"],0,"Article 19(1)(a) grants free speech; Article 19(2) allows reasonable restrictions.","Free speech exists but isn't absolute. Reasonable restrictions under 19(2).");
  add(3,"Constitution","The basic structure doctrine prevents:",["Parliament from altering fundamental constitutional features","Any amendment ever","Only the Preamble from changing","Judges from reviewing laws"],0,"Established in Kesavananda Bharati (1973). Democracy, secularism, federalism are basic structure.","Basic structure: even Parliament can't destroy core constitutional features.");
  add(3,"Constitution","India's Constitution has approximately:",["470 articles across 25 parts","100 articles","200 articles","1000 articles"],0,"Originally 395 articles. Now ~470 with amendments. One of the world's longest constitutions.","India's Constitution: ~470 articles, 25 parts, 12 schedules. World's longest.");
  add(3,"Constitution","Fundamental Duties are listed under:",["Article 51A","Article 14","Article 21","Article 32"],0,"Added by the 42nd Amendment (1976). 11 duties including respecting the Constitution and national symbols.","11 Fundamental Duties under 51A. Added in 1976. Know them as a citizen.");
  add(3,"Constitution","The 86th Amendment added:",["Right to Education as Article 21A","Right to privacy","Right to property","Right to information"],0,"Free and compulsory education for children aged 6-14 became a fundamental right in 2002.","Right to Education: 86th Amendment, 2002. Ages 6-14. Fundamental right.");
  add(3,"Consumer","National Consumer Helpline number is:",["1800-11-4000 (toll-free)","100","112","1098"],0,"File complaints, get guidance on rights, and seek redressal for consumer issues.","Consumer problems? Call 1800-11-4000 (free). Also file online at consumerhelpline.gov.in.");
  add(3,"Consumer","Misleading advertisements are punishable with:",["Fines up to Rs 10 lakh under Consumer Protection Act 2019","No legal consequences","Only moral guidelines","Only international law"],0,"The CCPA can impose penalties, order corrective advertisements, and ban misleading ads.","Misled by an ad? Report to CCPA. Fines up to Rs 10 lakh for advertisers.");
  add(3,"Consumer","If a product is defective, you can claim:",["Replacement, refund, or compensation under Consumer Protection Act","Nothing — you accepted it by buying","Only complain to manufacturer","Only exchange within 24 hours"],0,"Consumer rights include refund, replacement, compensation, and even product liability claims.","Defective product = your right to refund/replacement/compensation. Know the law.");
  add(3,"Consumer","Consumer complaints can now be filed:",["Online through e-Daakhil portal","Only in person at the district forum","Only through a lawyer","Only by post"],0,"e-Daakhil.nic.in allows online filing of consumer complaints from anywhere in India.","File consumer complaints from home: e-Daakhil.nic.in. No lawyer needed.");
  add(3,"Traffic","Drunk driving penalty can include:",["Up to Rs 10,000 fine and/or 6 months imprisonment","Rs 500 fine only","Just a warning","Only license suspension for a week"],0,"Repeat offense: Rs 15,000 and/or 2 years imprisonment. Zero tolerance policy.","Drunk driving: Rs 10K fine + 6 months jail. Repeat: Rs 15K + 2 years. Never worth it.");
  add(3,"Traffic","Driving without valid license in India attracts:",["Up to Rs 5,000 fine and/or 3 months imprisonment","Rs 100 fine","No penalty exists","Just a warning"],0,"Motor Vehicles Amendment Act 2019 significantly increased penalties for all violations.","No license: up to Rs 5,000 + 3 months jail. Always carry your license.");
  add(3,"Traffic","Wearing helmet while riding two-wheeler is:",["Mandatory by law for both rider and pillion, with penalties for violation","Optional for short distances","Required only on highways","Only mandatory for pillion"],0,"Helmets reduce head injury risk by 70% and death risk by 40%.","Helmet: mandatory + reduces death risk 40%. BOTH rider AND pillion.");
  add(3,"Cyber Law","Sharing private photos without consent is:",["Criminal offense under IT Act, imprisonment up to 3 years","Not covered by law","Only morally wrong","A civil matter only"],0,"Section 66E of IT Act. Victims can file FIR. Courts take this seriously.","Non-consensual image sharing: 3 years jail. File FIR under Section 66E IT Act.");
  add(3,"Cyber Law","Online identity theft is:",["Criminal offense under IT Act with imprisonment and fine","Just annoying","Not covered by law","Only a foreign problem"],0,"Identity theft for fraud attracts imprisonment up to 3 years and fine up to Rs 1 lakh.","Identity theft: criminal offense. Use unique passwords and 2FA to protect yourself.");
  add(3,"Police","An FIR can be filed at:",["Any police station in India regardless of jurisdiction","Only your local station","Only by the victim","Only through a lawyer"],0,"Zero FIR concept: any station must accept. Police cannot refuse to register an FIR.","FIR: file at ANY station. Police CANNOT refuse. This is your legal right.");
  add(3,"Police","A person arrested must appear before a magistrate within:",["24 hours of arrest","48 hours","72 hours","7 days"],0,"Article 22 of the Constitution. Violation of this is illegal detention.","Arrested → magistrate within 24 hours. Constitutional guarantee under Article 22.");
  add(3,"RTI","An RTI response must come within:",["30 days (48 hours if life/liberty is at stake)","7 days","60 days","90 days"],0,"RTI application costs just Rs 10. One of the most powerful citizen empowerment tools.","RTI: Rs 10 fee, 30-day response guaranteed. Powerful transparency tool.");
  add(3,"Governance","A PIL can be filed by:",["Any citizen on behalf of public interest, even if not personally affected","Only the victim","Only lawyers","Only NGOs"],0,"PILs have been used for environmental protection, human rights, and public welfare.","PIL: any citizen can file for public good. Powerful tool for justice.");
  add(3,"Governance","Lokpal investigates corruption at:",["Central government level among public servants","State level only","Municipal level only","International level"],0,"Lokpal (center) and Lokayuktas (states) were established under the 2013 Act.","Lokpal: anti-corruption at center. Lokayukta: at state level.");
  add(3,"Governance","Fast-track courts expedite:",["Trials of serious crimes like rape and murder","Only traffic cases","Only tax disputes","Only civil cases"],0,"Designed to deliver justice within 6-12 months instead of the years regular courts take.","Fast-track courts: serious crimes. Justice in months, not years.");
  add(3,"Women","POCSO Act protects:",["Children under 18 from sexual offenses","Only women from domestic violence","Only elderly from neglect","Only workers from harassment"],0,"Protection of Children from Sexual Offences Act (2012). Gender-neutral protection for all minors.","POCSO: protects ALL children under 18 from sexual abuse. Report: 1098.");
  add(3,"Women","Women helpline number in India is:",["181","100","112","1098"],0,"24/7 helpline for women in distress. Also accessible via WhatsApp in some states.","181: Women's helpline, 24/7. 1098: Child helpline. 112: Universal emergency.");

  // ─── DIGITAL: 60 questions ───
  add(4,"Privacy","Your digital footprint includes:",["Everything online: searches, posts, purchases, location data, even deleted content","Only social media posts","Only emails","Only photos"],0,"Companies, employers, and hackers can use your digital footprint. Be mindful of what you share.","Your digital footprint is permanent. Think before you post, click, or search.");
  add(4,"Privacy","Incognito browsing mode:",["Only prevents your browser from saving local history — ISP and websites still track you","Makes you anonymous online","Blocks all cookies forever","Encrypts your traffic"],0,"Your ISP, employer, and websites still see everything. For real privacy, use a VPN.","Incognito = local privacy only. ISP, websites, employer still see you.");
  add(4,"Privacy","Apps should only be granted permissions that:",["Are clearly necessary for the app's core function","Are always accepted without reading","Are always denied completely","Don't matter either way"],0,"A calculator needing contacts = red flag. A maps app needing location = reasonable.","Ask yourself: does this app NEED this permission to work? If not, deny it.");
  add(4,"Privacy","End-to-end encryption means:",["Only sender and recipient can read messages — not even the app provider","Only the sender can read it","Messages are backed up to cloud","Messages are faster"],0,"WhatsApp and Signal use E2E encryption. Even if intercepted, messages can't be decoded.","E2E encrypted: only you and recipient can read. WhatsApp, Signal have this.");
  add(4,"Privacy","Metadata in photos can reveal:",["Location, time, device model, and camera settings","Nothing useful","Only file size","Only resolution"],0,"Before sharing photos publicly, strip metadata. Many apps allow this in settings.","Photos contain hidden metadata: your location, time, device. Strip before sharing.");
  add(4,"Security","A VPN protects you by:",["Encrypting your internet traffic and hiding your IP address","Making internet faster","Blocking all ads","Replacing antivirus"],0,"Essential on public WiFi. Also helps bypass geo-restrictions on content.","VPN: encrypt your connection on public WiFi. Essential for security.");
  add(4,"Security","Zero-day vulnerabilities are dangerous because:",["No security patch exists yet since the flaw is unknown to the developer","They are already fixed","They only affect old software","They fix themselves"],0,"Hackers exploit these before developers know they exist. Keep all software updated.","Keep software updated. Zero-day = unknown flaw hackers find first.");
  add(4,"Security","Two-factor authentication is most secure with:",["An authenticator app or hardware key","SMS codes only","Email verification only","A second password"],0,"SMS codes can be intercepted via SIM swapping. Authenticator apps generate codes offline.","2FA: use Google Authenticator or Authy. More secure than SMS codes.");
  add(4,"Security","Before selling your old phone:",["Factory reset, remove SIM and SD card, sign out of all accounts","Just delete photos","Only remove SIM","Give it away as-is"],0,"A factory reset alone may not erase everything. Remove SIM, SD card, and sign out everywhere.","Selling phone: factory reset → remove SIM → remove SD → sign out of Google/Apple.");
  add(4,"AI","AI hallucinations means:",["AI generating confident but factually incorrect information","AI dreaming","Computer overheating","AI refusing to answer"],0,"Large language models can produce plausible-sounding but completely fabricated facts.","AI can be confidently wrong. Always verify important AI outputs.");
  add(4,"AI","Deepfake technology can:",["Create realistic fake videos making people appear to say things they never said","Only produce low-quality content","Only be used by governments","Only affect computers"],0,"Deepfakes threaten elections, relationships, and trust. Verify unconfirmed videos.","Deepfakes: even realistic video can be fabricated. Verify before believing.");
  add(4,"AI","AI bias comes from:",["Historical biases in the training data","AI being intentionally evil","Random computer errors","Users manipulating results"],0,"If training data reflects societal biases, AI amplifies them. Diverse data and testing are crucial.","AI inherits human biases from data. Always question AI decisions.");
  add(4,"Social Media","The filter bubble effect means:",["Algorithms show only content matching your existing views, limiting exposure to diverse perspectives","Using photo filters","Email spam filtering","Content moderation"],0,"Break the bubble: follow diverse sources, read opposing viewpoints, use different platforms.","Filter bubble: algorithms trap you in echo chambers. Seek diverse views actively.");
  add(4,"Social Media","Cyberbullying differs from traditional bullying because:",["It follows victims home, spreads virally, and happens 24/7","It is less harmful","It only affects adults","It always involves physical threats"],0,"Online harassment can be relentless. Save evidence, block, report, and tell a trusted adult.","Cyberbullying: screenshot everything → block → report → tell trusted adult.");
  add(4,"Social Media","Doom-scrolling refers to:",["Compulsively consuming negative news despite it worsening your mood","Scrolling through fun content","A social media game","A fast-scrolling technique"],0,"Negative news triggers dopamine hits while increasing anxiety. Set time limits on news apps.","Caught doom-scrolling? Set a timer. Limit news to 15 min twice daily.");
  add(4,"Fake News","The most reliable way to verify a news story is:",["Cross-check across multiple credible, independent sources","Check how many people shared it","See if the headline is convincing","Check if it confirms what you believe"],0,"No single source is infallible. Cross-reference Reuters, AP, established outlets.","Before sharing: check 3 sources. If only one says it, be skeptical.");
  add(4,"Digital Life","Blue light from screens before bed:",["Suppresses melatonin production, disrupting sleep","Has no effect on sleep","Helps you fall asleep faster","Only affects children"],0,"Use night mode after 8 PM. Better yet, stop screens 1 hour before bed.","Blue light = less melatonin = bad sleep. Night mode ON after 8 PM.");
  add(4,"Digital Life","The right to be forgotten allows:",["Requesting removal of personal information from search engines","Forgetting passwords","Deleting the entire internet","Erasing others' data"],0,"EU GDPR established this right. India's data protection law includes similar provisions.","You can request Google to remove outdated personal search results.");
  add(4,"Digital Life","Digital minimalism means:",["Intentionally using only technology that truly adds value to your life","Owning zero devices","Having the cheapest phone","Never using internet"],0,"Keep apps that serve you. Delete those that just consume your time and attention.","Digital minimalism: keep what adds value, delete what steals your time.");
  add(4,"Internet","Cloud storage means your files are:",["Stored on remote servers accessible via internet from any device","In actual clouds","Only on your device","Deleted after time"],0,"Google Drive, iCloud, OneDrive — your data is on someone else's computer. Understand the tradeoff.","Cloud = remote servers. Convenient but someone else holds your data.");

  // ─── CRITICAL THINKING: 60 questions ───
  add(9,"Logic","Correlation does not equal causation means:",["Two things happening together doesn't prove one causes the other","All correlations are meaningless","Causes are never found","Science is always wrong"],0,"Ice cream sales and drownings both rise in summer — heat causes both, not ice cream.","Correlation ≠ causation. Ask: is there a hidden third variable?");
  add(9,"Logic","The Dunning-Kruger effect describes:",["People with little knowledge overestimate their competence while experts underestimate theirs","Experts are always right","Beginners are always wrong","Intelligence can't be measured"],0,"The less you know, the less you realize you don't know. True expertise brings humility.","The less you know, the more confident you may incorrectly feel.");
  add(9,"Logic","The sunk cost fallacy makes people:",["Continue bad investments because of money already spent","Save money wisely","Always cut losses","Invest only in safe options"],0,"What's spent is spent. Future decisions should be based on future value, not past costs.","'I've already spent so much...' is a trap. Only future value matters.");
  add(9,"Logic","Confirmation bias means:",["Seeking information that confirms existing beliefs while ignoring contradicting evidence","Carefully verifying all facts","Being open to all viewpoints","Changing your mind easily"],0,"We naturally notice evidence supporting our views and ignore evidence against them.","Actively seek viewpoints that challenge what you already believe.");
  add(9,"Logic","The bandwagon effect describes:",["Adopting beliefs or behaviors because many others do, not based on evidence","Following expert advice","Making independent decisions","Being contrarian"],0,"Popularity doesn't equal truth. A million people believing something wrong doesn't make it right.","Popular ≠ correct. Think independently. A million lemmings can be wrong.");
  add(9,"Logic","Occam's Razor suggests:",["The simplest explanation fitting the evidence is usually correct","Complex explanations are always right","Simple things are always true","Never simplify"],0,"When multiple explanations work, start with the simplest. Add complexity only when needed.","Simplest explanation first. Add complexity only if evidence demands it.");
  add(9,"Logic","A straw man fallacy involves:",["Misrepresenting someone's argument to make it easier to attack","Building a strong argument","Using statistics","Quoting experts"],0,"Instead of addressing the real argument, you create a weaker version and attack that instead.","Straw man: attacking a distorted version of someone's argument. Spot it.");
  add(9,"Logic","Appeal to authority fallacy means:",["Claiming something is true just because a famous person said it","Never consulting experts","Ignoring all authority","Following experts blindly"],0,"Celebrity endorsement doesn't make a health product effective. Check the evidence, not the spokesperson.","Celebrity says it works? Check the EVIDENCE, not the endorser.");
  add(9,"Logic","The anchoring effect means:",["The first piece of information disproportionately influences judgment","Always using the best data","Starting with no assumptions","Being objective"],0,"Retailers show high 'original' prices first so 'sale' prices seem like bargains.","First number you see anchors your judgment. 'Was Rs 5000, now Rs 999!'");
  add(9,"Logic","False dilemma fallacy presents:",["Only two options when more alternatives exist","A genuine choice","An unsolvable problem","All available options"],0,"'You're either with us or against us' ignores nuance, neutrality, and partial agreement.","Reality has more than 2 options. Reject forced either/or thinking.");
  add(9,"Logic","Survivorship bias means:",["Focusing on successes while ignoring failures, creating a misleading picture","Studying all outcomes equally","Ignoring success stories","Analyzing only failures"],0,"We study billionaire dropouts but ignore millions who dropped out and failed.","Don't only study winners. The 90% who failed may have done the same things.");
  add(9,"Logic","The 'appeal to nature' fallacy assumes:",["Everything natural is automatically good and everything artificial is bad","Nature is complex","Some natural things are good","Science helps evaluate nature"],0,"Arsenic, poison ivy, and snake venom are all natural. Natural ≠ safe or good.","Natural ≠ good. Arsenic is natural. Vaccines are artificial. Judge by evidence.");
  add(9,"Logic","Circular reasoning is:",["Using the conclusion as evidence for itself","A productive argument cycle","Agreement among experts","Evidence-based reasoning"],0,"'This news is reliable because the source is trustworthy because their news is reliable.'","Spot circular logic: if the proof is just the claim restated, it proves nothing.");
  add(9,"Bias","The halo effect makes people:",["Assume someone good at one thing must be good at everything","Judge everyone equally","Be more critical","Always distrust first impressions"],0,"An attractive candidate may seem smarter in interviews. One good trait biases overall perception.","Good-looking ≠ good at job. One positive trait shouldn't color everything.");
  add(9,"Bias","Recency bias means:",["Giving too much weight to recent events when judging the future","Remembering the past clearly","Equal weighting of all data","Focusing only on ancient history"],0,"Stock market: last month's performance doesn't predict next month's. Look at long-term trends.","Don't overweight recent events. Consider the full picture and long-term data.");
  add(9,"Bias","The Dunning-Kruger peak happens when someone:",["Has just a little knowledge and greatly overestimates their competence","Is an expert","Knows nothing at all","Has moderate experience"],0,"A dangerous zone: enough knowledge to feel confident, not enough to know what you're missing.","Most dangerous: knowing a little and thinking you know a lot.");
  add(9,"Decision","Analysis paralysis is overcome by:",["Setting a decision deadline and accepting that perfect info is rarely available","Gathering infinite data","Avoiding all analysis","Always flipping a coin"],0,"A good decision made on time beats a perfect decision made too late.","Deadline + decide. 80% information is enough. Perfect is the enemy of good.");
  add(9,"Decision","The 10-10-10 rule asks:",["How will you feel about this decision in 10 minutes, 10 months, 10 years?","What 10 people think","If it takes 10 steps","How much it costs times 10"],0,"Great for emotional decisions. Often what seems huge now matters little in 10 months.","Big decision? Ask: will this matter in 10 minutes? 10 months? 10 years?");
  add(9,"Decision","Second-order thinking considers:",["Not just direct consequences but the consequences of those consequences","Only immediate effects","Second opinions","Two options"],0,"First order: this dessert tastes good. Second order: eating it daily causes weight gain and diabetes.","Think two steps ahead. What happens after what happens?");
  add(9,"Ethics","The bystander effect means:",["People are less likely to help when others are present","Bystanders always help","Standing by is always safe","Witnesses are always accurate"],0,"In crowds, everyone assumes someone else will act. Break the effect: specifically ask ONE person for help.","Bystander effect: in crowds, point at ONE person and say 'YOU, call 112.'");
  add(9,"Ethics","The tragedy of the commons describes:",["Individual self-interest depleting shared resources and harming everyone","Well-maintained public spaces","Unlimited resources","Perfect cooperation"],0,"Overfishing, pollution, traffic — each person acts rationally but the collective outcome is disaster.","Shared resources + unchecked self-interest = everyone loses. Cooperate.");
  add(9,"Ethics","Cognitive dissonance is:",["Mental discomfort when your actions contradict your beliefs","Harmonious thinking","A brain disorder","Perfect logic"],0,"Knowing smoking kills but continuing to smoke creates internal tension your brain tries to resolve.","When actions don't match beliefs, you feel tension. Use it as a signal to change.");
  add(9,"Mental Models","First-principles thinking means:",["Breaking problems to their most basic truths and building up from there","Following tradition always","Copying what others do","Accepting things as they are"],0,"Instead of 'how have others solved this?', ask 'what are the fundamental truths here?'","First principles: don't ask 'how is it done?' Ask 'why is it done this way?'");
  add(9,"Mental Models","The Pareto principle (80/20 rule) states:",["Roughly 80% of results come from 20% of efforts","Everything is equally important","50-50 split always","100% effort = 100% results"],0,"Identify the vital 20% of your work that produces 80% of results. Focus there.","Find your 20% that drives 80% of results. Focus ruthlessly.");
  add(9,"Mental Models","The paradox of choice describes:",["Too many options causing anxiety, indecision, and lower satisfaction","More choices always being better","Choices being easy","People preferring no choice"],0,"Limit your options for better decisions. Set criteria, shortlist 3-5, then choose.","Too many choices? Set criteria first, then shortlist to 3 max.");

  // ─── GOVERNANCE: 60 questions ───
  add(10,"Governance","Question Hour in Parliament is:",["The first hour when MPs question ministers about government functioning","A quiz show","A private session","An informal chat"],0,"Holds government accountable. Happens at the start of each parliamentary sitting.","Question Hour: MPs hold ministers accountable. Key democracy mechanism.");
  add(10,"Governance","FSSAI regulates:",["Food safety and standards in India","Factory safety","Financial services","Foreign policy"],0,"FSSAI licenses food businesses and sets safety standards. Check the FSSAI logo on packaged food.","FSSAI logo on food = safety checked. Look for the license number.");
  add(10,"Governance","TRAI regulates:",["Telecom and broadcasting sector in India","Transport","Tourism","Trade"],0,"TRAI ensures fair telecom practices, regulates tariffs, and protects consumer interests.","TRAI: protects your rights as a telecom consumer. File complaints on their portal.");
  add(10,"Governance","A no-confidence motion can be moved in:",["Lok Sabha only","Rajya Sabha only","Both houses","Any state assembly"],0,"If passed by majority, the government must resign. PM is responsible to Lok Sabha.","No-confidence motion: Lok Sabha only. If passed, government falls.");
  add(10,"Governance","Rajya Sabha can delay a Money Bill for:",["Maximum 14 days","30 days","60 days","90 days"],0,"After 14 days, it's deemed passed with or without Rajya Sabha's approval.","Money Bills: Rajya Sabha gets just 14 days. Lok Sabha has supremacy.");
  add(10,"Governance","Vice President is ex-officio Chairman of:",["Rajya Sabha","Lok Sabha","NITI Aayog","Supreme Court"],0,"The VP presides over Rajya Sabha proceedings and maintains order in the house.","VP = Chairman of Rajya Sabha. Speaker = head of Lok Sabha.");
  add(10,"Governance","Speaker of Lok Sabha votes:",["Only in case of a tie (casting vote)","On every issue","Never","Only on money bills"],0,"The Speaker maintains neutrality and only votes to break a deadlock.","Speaker's casting vote: only used to break a tie. Maintains neutrality.");
  add(10,"Governance","Minimum age to become President of India:",["35 years","25 years","40 years","50 years"],0,"Must be a citizen of India, at least 35, and qualified to be a Lok Sabha member.","President: minimum 35. PM: minimum 25 (Lok Sabha age). Rajya Sabha: 30.");
  add(10,"Governance","India has how many High Courts?",["25","15","30","35"],0,"25 High Courts, some with jurisdiction over multiple states and UTs.","25 High Courts across India. Supreme Court is the apex court in Delhi.");
  add(10,"Governance","The Finance Commission recommends:",["Distribution of tax revenues between center and states","Foreign policy","Military strategy","Education curriculum"],0,"Constituted every 5 years to ensure fiscal federalism and fair revenue sharing.","Finance Commission: ensures states get fair share of tax revenue.");
  add(10,"Governance","The Attorney General is:",["The chief legal advisor to the Government of India","A Supreme Court judge","The army chief","An elected representative"],0,"Can participate in Parliamentary proceedings but cannot vote. Appointed by the President.","AG: government's top lawyer. Can speak in Parliament but can't vote.");
  add(10,"Governance","The difference between state and Union Territory:",["States have elected governments; UTs are primarily governed by the center","No difference","UTs are larger","States have no legislature"],0,"Delhi and Puducherry are exceptions — UTs with elected legislatures and Chief Ministers.","States = own government. UTs = center governs (Delhi and Puducherry are exceptions).");
  add(10,"Governance","Panchayati Raj has three tiers:",["Gram Panchayat, Block Panchayat, and Zila Parishad","Village, City, State","Ward, Zone, Division","Town, District, Capital"],0,"73rd Amendment (1992) constitutionalized local self-governance in rural India.","3 tiers: Gram (village) → Block → Zila (district). Grassroots democracy.");
  add(10,"Governance","Anti-defection law is in:",["Tenth Schedule of the Constitution","First Schedule","Fifth Schedule","Eighth Schedule"],0,"Prevents elected members from switching parties. A member defecting can be disqualified.","10th Schedule: switch parties after election = disqualified. Anti-defection.");
  add(10,"Governance","CBI investigates:",["Major crimes including corruption, fraud, and cases of national importance","Only traffic violations","Only state-level crimes","Only consumer complaints"],0,"CBI operates under the Delhi Special Police Establishment Act. Requires state consent for state cases.","CBI: investigates corruption, economic crime, and special cases of national importance.");
  add(10,"Governance","CVC addresses:",["Corruption in central government departments","Environmental pollution","Consumer complaints","Criminal cases"],0,"Central Vigilance Commission is an independent body fighting government corruption.","CVC: anti-corruption watchdog for central government. File complaints on their website.");
  add(10,"International","WTO is headquartered in:",["Geneva, Switzerland","New York, USA","Washington DC","Brussels"],0,"WTO deals with international trade rules between nations.","WTO: Geneva. UN: New York. World Bank/IMF: Washington DC. WHO: Geneva.");
  add(10,"International","WHO is headquartered in:",["Geneva, Switzerland","New York","London","Paris"],0,"World Health Organization coordinates international public health from Geneva.","WHO: Geneva. The UN's global health authority.");
  add(10,"International","G20 members represent approximately:",["85% of global GDP","50% of GDP","30% of GDP","95% of GDP"],0,"India hosted the G20 presidency in 2023. Includes both developed and developing economies.","G20: 85% of global GDP. India hosted in 2023. Powerful economic forum.");
  add(10,"International","UNICEF works primarily for:",["Rights, health, education, and protection of children worldwide","International trade","Environmental conservation","Space exploration"],0,"UNICEF operates in over 190 countries. Focus: child survival, development, and protection.","UNICEF: children's rights in 190+ countries. Health, education, protection.");

