  add(11,"Awareness","Mars appears red because of:",["Iron oxide (rust) in its soil","Oxygen","CO2","Nitrogen"],0,"Iron oxide (rust) in its soil.","Iron oxide (rust) in its soil.");
  add(11,"Awareness","Which country gifted the Statue of Liberty to USA?",["France","Britain","Germany","Spain"],0,"France.","France.");
  add(11,"Awareness","Yuri Gagarin was the first human to:",["Travel to outer space (1961)","Walk on Moon","Discover a planet","Build a rocket"],0,"Travel to outer space (1961).","Travel to outer space (1961).");
  add(11,"Awareness","Ada Lovelace is considered the first:",["Computer programmer in history","Scientist","Doctor","Astronaut"],0,"Computer programmer in history.","Computer programmer in history.");
  add(11,"Awareness","The age of the universe is approximately:",["13.8 billion years","4.5 billion years","1 million years","100 billion years"],0,"13.8 billion years.","13.8 billion years.");
  add(11,"Awareness","A nautical mile is:",["1.852 kilometers — based on Earth's circumference","Same as a regular mile","Shorter than a km","100 meters"],0,"1.852 kilometers — based on Earth's circumference.","1.852 kilometers — based on Earth's circumference.");
  add(11,"Awareness","The blood of horseshoe crabs is:",["Blue due to copper-based hemocyanin","Red like humans","Green","Clear"],0,"Blue due to copper-based hemocyanin.","Blue due to copper-based hemocyanin.");
  add(11,"Awareness","An adult human produces about how many red blood cells per second?",["About 2 million","100","10,000","500"],0,"About 2 million.","About 2 million.");
  add(11,"Awareness","The human eye blinks approximately:",["15,000-20,000 times per day","1,000","5,000","50,000"],0,"15,000-20,000 times per day.","15,000-20,000 times per day.");
  add(11,"Awareness","A chameleon changes color mainly to:",["Communicate, regulate temperature, and respond to mood","Match any background exactly","Hide from predators only","Attract prey"],0,"Communicate, regulate temperature, and respond to mood.","Communicate, regulate temperature, and respond to mood.");
  add(11,"Awareness","A hummingbird can fly:",["Forward, backward, and hover in place","Only forward","Only in circles","Only upward"],0,"Forward, backward, and hover in place.","Forward, backward, and hover in place.");
  add(11,"Awareness","Polar bear fur is actually:",["Transparent and hollow, not white","Pure white","Gray","Brown"],0,"Transparent and hollow, not white.","Transparent and hollow, not white.");
  add(11,"Awareness","Honey bees communicate food locations through:",["A waggle dance","Singing","Changing color","Only pheromones"],0,"A waggle dance.","A waggle dance.");
  add(11,"Awareness","The most electrically conductive metal is:",["Silver","Gold","Copper","Aluminum"],0,"Silver.","Silver.");
  add(11,"Awareness","Pearls form inside:",["Oysters and certain mollusks","Rocks","Coral","Seashells on beaches"],0,"Oysters and certain mollusks.","Oysters and certain mollusks.");
  add(11,"Awareness","The country producing most coffee is:",["Brazil","India","Colombia","Ethiopia"],0,"Brazil.","Brazil.");
  add(11,"Awareness","The country producing most tea is:",["China","India","Sri Lanka","Kenya"],0,"China.","China.");
  add(11,"Awareness","Saffron, the most expensive spice, mainly comes from:",["Iran","India","Spain","Italy"],0,"Iran.","Iran.");
  add(11,"Awareness","The Dead Sea is famous for:",["Extreme salinity allowing people to float easily","Being very deep","Having no water","Being the largest sea"],0,"Extreme salinity allowing people to float easily.","Extreme salinity allowing people to float easily.");

  // ═══ VERIFIED BATCH 5: 242 questions (all cor=0 verified) ═══
  add(0,"Nutrition","Millets like jowar bajra and ragi are gaining popularity because they are:",["Nutrient-dense gluten-free and require less water to grow","Tastier than rice","Only available in India","More expensive than quinoa"],0,"Millets are rich in fiber iron and calcium. They are also climate-resilient crops.","Millets: nutrient-rich climate-friendly. India is promoting them globally.");
  add(0,"Nutrition","The best time to eat fruits is:",["In the morning or between meals","Late at night before sleeping","Immediately after a heavy meal","Only on weekends"],0,"Fruits are best absorbed on an empty or semi-empty stomach for maximum nutrient uptake.","Eat fruits between meals or morning for best absorption.");
  add(0,"Nutrition","Coconut water is a natural source of:",["Electrolytes including potassium sodium and magnesium","Protein","Iron","Vitamin D"],0,"Great for rehydration after exercise or illness. Low calorie and naturally fat-free.","Coconut water: natural electrolyte drink. Better than most sports drinks.");
  add(0,"Nutrition","Processed foods are generally unhealthy because they contain:",["Excess salt sugar unhealthy fats and artificial additives","Too many vitamins","Too much protein","Too much fiber"],0,"Ultra-processed foods are linked to obesity heart disease and some cancers.","Read food labels: high sodium sugar or long ingredient lists = ultra-processed.");
  add(0,"Nutrition","Caffeine has a half-life of approximately:",["5-6 hours meaning half is still active hours later","30 minutes","24 hours","1 hour"],0,"An afternoon coffee at 3 PM means half the caffeine is still active at 9 PM affecting sleep.","Avoid caffeine after 2 PM. Half is still active 5-6 hours later.");
  add(0,"Diseases","Urinary tract infections (UTIs) are more common in:",["Women due to shorter urethral length","Only elderly men","Only children","Only athletes"],0,"Drink plenty of water and maintain hygiene to prevent UTIs. See a doctor if symptoms persist.","UTIs: more common in women. Drink water maintain hygiene. See doctor for symptoms.");
  add(0,"Diseases","Epilepsy is characterized by:",["Recurrent seizures from abnormal electrical brain activity","Constant headaches","Joint pain","Skin rashes"],0,"Epilepsy is manageable with medication. First aid: clear area protect head time the seizure.","Epilepsy: manageable with medication. During seizure: protect head clear area.");
  add(0,"Diseases","Psoriasis is a chronic condition affecting the:",["Skin causing red scaly patches that can be itchy","Lungs","Heart","Liver"],0,"Psoriasis is an autoimmune condition. Not contagious. Triggered by stress infection or weather.","Psoriasis: autoimmune skin condition. NOT contagious. Treatable.");
  add(0,"Diseases","The most common cause of peptic ulcers is:",["H. pylori bacteria and overuse of NSAIDs like ibuprofen","Spicy food alone","Stress alone","Drinking cold water"],0,"The myth that spicy food causes ulcers was debunked. Bacteria and painkillers are the real causes.","Ulcers: caused by bacteria and painkillers NOT spicy food.");
  add(0,"Body","The human body replaces most cells every:",["7-10 years on average though different cells have different lifespans","1 day","1 week","Never — cells last forever"],0,"Stomach lining replaces in days. Red blood cells in 120 days. Some neurons last a lifetime.","Your body constantly rebuilds. Most cells replaced within 7-10 years.");
  add(0,"Body","Red blood cells live for approximately:",["120 days before being replaced by new ones from bone marrow","1 day","1 year","Forever"],0,"Your bone marrow produces about 2 million new red blood cells every second.","Red blood cells: 120-day lifespan. 2 million new ones made every second.");
  add(0,"Body","The largest gland in the human body is the:",["Liver which performs over 500 functions","Thyroid","Pituitary","Adrenal"],0,"The liver detoxifies blood produces bile stores nutrients and processes medications.","Liver: largest gland. 500+ functions including detox and bile production.");
  add(0,"Body","Insulin is produced by the:",["Pancreas to regulate blood sugar levels","Liver","Thyroid","Adrenal glands"],0,"Insulin helps cells absorb glucose from blood. Dysfunction leads to diabetes.","Pancreas makes insulin. Insulin controls blood sugar. Dysfunction = diabetes.");
  add(0,"Body","The cornea is part of the:",["Eye — it is the clear front surface that helps focus light","Ear","Nose","Skin"],0,"The cornea provides about 65-75% of the eye's total focusing power.","Cornea: clear front of eye. Provides most of your eye's focusing power.");
  add(0,"Mental","Social media overuse has been linked to:",["Increased anxiety depression and poor body image especially in teenagers","Only better social connections","Improved academic performance","Better sleep quality"],0,"Studies show correlation between heavy social media use and mental health issues in teens.","Monitor teen screen time. Social media affects self-esteem and sleep.");
  add(0,"Mental","The recommended screen time for children aged 2-5 is:",["No more than 1 hour per day of quality content","Unlimited if educational","At least 4 hours daily","Screen time has no effect"],0,"Excessive screen time delays language development and reduces physical activity.","Children 2-5: max 1 hour quality screen time daily.");
  add(0,"Vaccines","Flu vaccines are recommended:",["Annually because influenza viruses mutate every year","Once in a lifetime","Only during pandemics","Never for healthy people"],0,"Flu strains change yearly. Annual vaccination reduces severity and hospitalization.","Get flu shot yearly. The virus changes — last year's vaccine won't fully protect.");
  add(0,"Vaccines","The BCG vaccine given at birth protects against:",["Tuberculosis especially severe forms in children","Polio","Hepatitis B","Measles"],0,"BCG (Bacillus Calmette-Guerin) is part of India's universal immunization programme.","BCG at birth: protects against TB. Part of routine immunization.");
  add(1,"Road","Seat belt use in rear seats:",["Is mandatory by law and reduces fatality risk significantly","Is optional always","Is only required on highways","Is only for children"],0,"Unbelted rear passengers become projectiles in crashes injuring front occupants too.","Rear seat belts: mandatory + lifesaving. Protects you AND front passengers.");
  add(1,"Road","When an ambulance approaches from behind:",["Slow down and pull to the left to let it pass","Speed up to get ahead","Stop in the middle of the road","Ignore it"],0,"Every minute of delay can cost a patient's life. Pull left and let them pass.","Give way to ambulances. Pull left. Someone's life depends on it.");
  add(1,"Road","The golden hour in accident response is:",["The first 60 minutes when medical treatment is most effective","Rush hour traffic","Sunset driving time","Peak accident time"],0,"Getting victims to hospital within 60 minutes dramatically improves survival.","Golden hour: first 60 min after accident. Quick treatment saves lives.");
  add(1,"Road","Lane discipline means:",["Staying in your lane and using indicators before changing","Driving in any lane you prefer","Only using the fast lane","Driving in the center"],0,"Poor lane discipline causes many accidents. Always indicate before changing lanes.","Stay in lane. Indicate before changing. Lane discipline saves lives.");
  add(1,"Road","Two-wheeler riders should wear:",["ISI-marked full-face helmets with chin strap fastened for both rider and pillion","Any hat or cap","Helmets only on highways","Open helmets without straps"],0,"Full-face helmets protect the chin and jaw injured in 35% of motorcycle crashes.","Full-face ISI helmet with strap. BOTH rider and pillion. Mandatory by law.");
  add(1,"Road","Speed breakers exist to:",["Slow traffic near schools hospitals and residential areas to protect pedestrians","Annoy drivers","Damage vehicles","Increase fuel consumption"],0,"Speed breakers save lives in high-pedestrian areas. Slow down over them.","Slow down at speed breakers. They protect children and pedestrians.");
  add(1,"Road","Night driving is more dangerous because:",["Reduced visibility and higher chance of drowsy or impaired drivers","Roads change at night","Cars perform poorly","Traffic rules change"],0,"Fatal crashes are 3x more likely at night. Reduce speed and stay alert.","Night driving: 3x more fatal. Reduce speed. Stay fully alert.");
  add(1,"Road","Using high beam in city traffic:",["Blinds oncoming drivers causing momentary loss of vision","Uses more fuel","Damages headlights","Is not bright enough"],0,"Switch to low beam when vehicles approach. High beam is for dark empty roads only.","High beam: only on dark empty roads. In traffic it blinds and kills.");
  add(1,"Cyber","If someone calls claiming your Aadhaar is misused demanding money:",["Hang up — no government body demands money over phone. This is a scam","Pay immediately","Share your Aadhaar to verify","Transfer money to avoid arrest"],0,"UIDAI never calls demanding money. Report scam calls at cybercrime.gov.in.","Aadhaar scam call: HANG UP. Report at cybercrime.gov.in.");
  add(1,"Cyber","SIM swapping fraud starts when scammers:",["Convince your mobile carrier to transfer your number to their SIM card","Steal your physical SIM from your phone","Clone your phone remotely","Hack your WiFi router"],0,"If your SIM suddenly stops working contact your carrier immediately.","SIM stops working? Call carrier IMMEDIATELY. Possible SIM swap.");
  add(1,"Cyber","Deepfake videos can be spotted by looking for:",["Unnatural blinking lip sync issues and odd skin texture","Perfect quality always means deepfake","Only AI can detect them","They are always obvious"],0,"Check face edges blinking patterns and whether lip sync matches audio.","Spotting deepfakes: check blinking lip sync skin texture face edges.");
  add(1,"Cyber","A strong password should be:",["At least 12 characters with uppercase lowercase numbers and symbols","Your name and birth year","Just numbers for simplicity","A common dictionary word"],0,"Use a unique password for each account. Consider a password manager.","12+ chars mixed types. Unique per account. Use a password manager.");
  add(1,"Cyber","Free public WiFi should not be used for:",["Banking or entering passwords without a VPN","Browsing news","Checking weather","Reading articles"],0,"Hackers intercept data on unencrypted public WiFi. Use mobile data for sensitive tasks.","Public WiFi: browse only. Mobile data or VPN for banking.");
  add(1,"Disaster","During a lightning storm you should avoid:",["Standing under tall trees or in open fields near water or metal","Staying inside a building","Being in a car with windows closed","Crouching low in a ditch"],0,"Lightning strikes the tallest point. Stay indoors. If outside crouch low away from trees.","Lightning: stay indoors. Outside? Crouch low away from trees water metal.");
  add(1,"Disaster","Earthquake preparedness includes:",["Securing heavy furniture to walls and having an escape plan","Only having an emergency kit","Nothing — earthquakes cannot be prepared for","Only stocking food"],0,"Secure bookshelves TVs water heaters. Practice Drop Cover Hold On drills.","Bolt furniture. Know exits. Practice Drop Cover Hold On.");
  add(1,"Disaster","Heat wave safety includes:",["Staying hydrated staying indoors during peak heat and wearing light clothing","Exercising outdoors at noon","Drinking only cold beverages","Taking ice baths constantly"],0,"Drink water even when not thirsty. Avoid sun between 11 AM and 4 PM.","Heat wave: hydrate constantly. Stay indoors 11AM-4PM. Light loose clothes.");
  add(1,"Disaster","After a flood only drink:",["Boiled or purified water as regular sources are contaminated","Any available water","River water","Rainwater from during the flood"],0,"Floods contaminate water with sewage and chemicals. Boil for 1 minute minimum.","Post-flood: BOIL water minimum 1 minute. Regular sources are contaminated.");
  add(1,"Travel","When using ride-sharing apps at night:",["Verify car model license plate and driver name before entering","Get into any car that stops","Only check the car color","Trust anyone in uniform"],0,"Share live trip with trusted contact. Sit in back seat.","Verify car details BEFORE entering. Share trip. Sit in back.");
  add(1,"Travel","Travel insurance is important because:",["It covers medical emergencies trip cancellations and lost baggage","It is a waste of money","It is legally required everywhere","It only covers flight delays"],0,"A medical emergency abroad without insurance can cost lakhs.","Travel insurance: one accident abroad can bankrupt you. Always get covered.");
  add(2,"Saving","The 50-30-20 rule allocates income as:",["50% needs 30% wants 20% savings and debt repayment","50% savings 30% needs 20% wants","Equal thirds","80% spending 20% taxes"],0,"Needs: rent food utilities. Wants: dining entertainment. Savings: investments emergency fund.","50-30-20: needs wants savings. Simple effective budgeting.");
  add(2,"Saving","An emergency fund should cover:",["3-6 months of living expenses","1 month","Only medical costs","1 week"],0,"This buffer protects against job loss medical emergencies and unexpected costs.","Build 3-6 months expenses as emergency fund BEFORE investing.");
  add(2,"Saving","Paying yourself first means:",["Automatically saving a fixed amount before spending on anything else","Buying things before paying bills","Earning extra income","Paying bills early"],0,"Set up auto-transfer to savings on salary day. Spend what remains.","Salary day: auto-transfer savings FIRST. Spend what's left.");
  add(2,"Saving","The latte factor teaches that:",["Small daily expenses compound into huge amounts over years","Coffee is unhealthy","Only large expenses matter","Small expenses are irrelevant"],0,"Rs 100/day = Rs 36500/year. Invested at 12% for 20 years = Rs 26 lakh.","Rs 100/day saved = Rs 26 lakh in 20 years invested. Small leaks sink ships.");
  add(2,"Banking","A fixed deposit gives higher interest because:",["Your money is locked for a fixed period letting the bank plan its lending","Banks are generous","FDs have zero risk","FDs are government guaranteed"],0,"Longer lock-in periods generally earn higher interest rates.","FD: higher interest but locked money. Choose tenure wisely.");
  add(2,"Banking","IMPS allows instant transfers:",["24x7 including holidays up to Rs 5 lakh","Only during banking hours","Only on weekdays","Once a week"],0,"IMPS works round the clock. UPI also works 24x7.","IMPS and UPI: 24x7. NEFT: batches during hours. RTGS: real-time for Rs 2L+.");
  add(2,"Banking","A cheque bounce is:",["A criminal offense under Section 138 Negotiable Instruments Act","Just inconvenient","Only the bank's problem","Free of penalty"],0,"Bounced cheques can lead to fines and imprisonment.","Bounced cheque = criminal offense. Always ensure sufficient balance.");
  add(2,"Investment","Compound interest grows money because:",["Interest is earned on both the principal AND previously accumulated interest","It pays higher rates","Banks add bonus amounts","Government subsidizes returns"],0,"Rs 1 lakh at 10%: Year 1 = Rs 10K interest. Year 10 = Rs 23.6K interest.","Compound interest: interest on interest. Time is the multiplier. Start early.");
  add(2,"Investment","Asset allocation should be based on:",["Your age risk tolerance financial goals and time horizon","Only following friends","Always 100% stocks","Only FDs"],0,"Rule of thumb: equity% = 100 minus age. Adjust for your risk tolerance.","Simple: equity% = 100 minus age. 30 years old = 70% equity 30% debt.");
  add(2,"Investment","PPF is attractive because:",["Government-backed safety with tax-free interest and 80C benefits","It has no lock-in","It gives 20% returns","Only for government employees"],0,"15-year lock-in. EEE status: exempt at investment interest and withdrawal.","PPF: safe + tax-free + 80C. 15-year lock-in. Start early.");
  add(2,"Investment","Diversification reduces risk by:",["Spreading investments across different assets so poor performance in one is offset by others","Concentrating in one stock","Eliminating all risk","Only investing in gold"],0,"Don't put all eggs in one basket. Mix equity debt gold.","Diversify: equity + debt + gold. No single point of failure.");
  add(2,"Investment","A bear market means stocks fell:",["20% or more from recent highs signaling pessimism","5% from highs","Any small amount","Exactly 10%"],0,"Bear markets are normal and temporary. Best time to buy through SIPs.","Bear market: 20%+ decline. Long-term investors: keep SIPs running.");
  add(2,"Investment","A bull market means stocks are:",["Rising 20% or more with widespread optimism","Falling sharply","Completely flat","Unpredictable"],0,"Bull markets can last years. Stay invested but don't over-leverage.","Bull market: rising prices. Stay invested but maintain discipline.");
  add(2,"Investment","Market timing is:",["Extremely difficult — even professionals fail. Time IN the market beats timing","Easy with practice","Always successful for experts","Only for beginners"],0,"Missing 10 best trading days over 20 years cuts returns by more than half.","Time IN market > timing market. Stay invested through SIPs.");
  add(2,"Insurance","Health insurance sum insured should be:",["At least Rs 5-10 lakh considering rising medical costs","Rs 1 lakh","Rs 50000","Not needed"],0,"Single hospitalization can cost Rs 5-10 lakh. Medical inflation is 15%/year.","Health insurance: minimum Rs 5-10L cover. Medical costs are exploding.");
  add(2,"Insurance","Cashless hospitalization means:",["Insurance company pays the hospital directly so you don't pay from pocket","Hospital is free","You pay cash","Only government hospitals"],0,"Works at network hospitals. Keep insurance card in wallet always.","Cashless: insurer pays hospital. Only at network hospitals. Carry your card.");
  add(2,"Insurance","Life insurance is most needed by:",["People with financial dependents like spouse children or aging parents","Single people with no dependents","Only wealthy people","Only elderly"],0,"Buy term insurance worth 10-15x annual income if anyone depends on your income.","Dependents? Term insurance = 10-15x annual income. Non-negotiable.");
  add(2,"Insurance","A deductible in health insurance is:",["The amount you pay from pocket before insurance coverage starts","Free coverage","The premium","Maximum coverage"],0,"Higher deductible = lower premium. Choose based on financial capacity.","Deductible = your share before insurer pays. Higher deductible = lower premium.");
  add(2,"Tax","Section 80D allows deduction for:",["Health insurance premiums up to Rs 25000 self and Rs 50000 senior parents","Home loan interest","Education loans","Donations"],0,"Both individual and family health insurance premiums qualify under 80D.","80D: health premium deduction. Rs 25K self + Rs 50K parents = Rs 75K total.");
  add(2,"Tax","Capital gains on equity held over 12 months:",["Taxed at 10% on gains above Rs 1 lakh per year","No tax at all","30% flat","Same as income tax slab"],0,"Short-term equity gains (under 12 months) are taxed at 15%.","LTCG equity: 10% above Rs 1L. STCG: 15%. Hold longer pay less.");
  add(2,"Tax","TDS stands for:",["Tax Deducted at Source — automatically cut from income before you receive it","Total Deduction Summary","Transaction Debit Statement","Taxable Deduction Savings"],0,"Employer or bank deducts TDS and deposits with government. File ITR for refunds.","TDS auto-deducted from salary/interest. File ITR to claim refund if excess.");
  add(2,"Fraud","Fake loan apps can be identified by:",["Asking access to contacts photos and gallery which is unnecessary for lending","They are all safe on stores","They follow RBI guidelines","They charge standard rates"],0,"Real lenders don't need gallery or contacts. Check RBI registration.","Loan app wants contacts/gallery? RED FLAG. Check RBI license first.");
  add(2,"Fraud","Cryptocurrency scams often promise:",["Guaranteed extremely high returns with zero risk","Normal returns with risk disclosure","Low returns","No returns"],0,"No investment can guarantee high returns without risk. All crypto involves risk.","Guaranteed crypto returns = scam. 100% of the time. No exceptions.");
  add(2,"Fraud","Unknown money received in your account — safest response:",["Do not touch it and inform your bank immediately as it may be fraud","Spend it immediately","Return it via UPI","Ignore it"],0,"Spending unknown deposits can make you part of a money laundering chain.","Unknown money: DO NOT touch. Call bank. Could be fraud setup.");
  add(3,"Rights","Article 21 guarantees:",["Right to life and personal liberty","Right to equality only","Right to education only","Right to property"],0,"The broadest right — courts expanded it to include dignity privacy livelihood.","Article 21: life + liberty. Expanded to dignity privacy livelihood.");
  add(3,"Rights","The Right to Education Act makes education:",["Free and compulsory for children aged 6-14","Optional","Free only in private schools","Compulsory until 18"],0,"Schools must reserve 25% seats for economically weaker sections.","RTE: free compulsory education ages 6-14. 25% seats for EWS.");
  add(3,"Rights","Article 32 is called the heart of the Constitution because:",["Citizens can directly approach Supreme Court for fundamental rights violations","It defines citizenship","It lists Directive Principles","It establishes Parliament"],0,"Dr. Ambedkar called Article 32 the heart and soul of the Constitution.","Article 32: direct access to Supreme Court for rights. Heart of Constitution.");
  add(3,"Constitution","The Preamble describes India as:",["A Sovereign Socialist Secular Democratic Republic","A Hindu nation","A monarchy","A federal state only"],0,"These five words define India's constitutional identity and values.","Sovereign Socialist Secular Democratic Republic. Know each word's meaning.");
  add(3,"Constitution","Fundamental Rights are in:",["Part III of the Constitution","Part I","Part IV","Part V"],0,"6 rights: equality freedom exploitation religion culture remedies.","Part III: your 6 Fundamental Rights. Know them use them.");
  add(3,"Constitution","The Constitution was adopted on:",["November 26 1949 now celebrated as Constitution Day","January 26 1950","August 15 1947","October 2 1950"],0,"It came into effect January 26 1950 — Republic Day.","Adopted Nov 26 1949. Effective Jan 26 1950. Two key dates.");
  add(3,"Constitution","Constitutional amendments require:",["Special majority of 2/3 members present and voting in both houses","Simple majority","Unanimous vote","Public referendum"],0,"Some amendments also need ratification by half the state legislatures.","Amendment: 2/3 majority both houses. Very high bar by design.");
  add(3,"Consumer","E-commerce companies must:",["Display total price provide return policies and address grievances","Operate without rules","Only list products","Deliver in 1 hour always"],0,"Consumer Protection E-Commerce Rules 2020 regulate all online sellers.","Online sellers must show total price including charges. Your right.");
  add(3,"Traffic","Hit and run can lead to:",["Up to 10 years imprisonment under IPC provisions","Only a fine","No legal consequence","License cancellation only"],0,"Hit and run is serious crime. Always stop render help and report.","Hit and run: up to 10 years jail. STOP. Help injured. Call 112.");
  add(3,"Traffic","Using mobile while driving attracts:",["Fine of Rs 1000 to Rs 5000 depending on state","Rs 100 fine","No fine","Warning only"],0,"Distracted driving is a major killer on Indian roads.","Phone while driving: Rs 1000-5000 fine. Not worth a life.");
  add(3,"Governance","An ordinance is:",["A temporary law issued by President when Parliament is not in session","A permanent law","A court order","A police directive"],0,"Must be approved by Parliament within 6 weeks or it expires.","Ordinance: temporary law. Expires in 6 weeks without Parliament approval.");
  add(3,"Governance","The Election Commission ensures:",["Free and fair elections in India","Budget allocation","Law enforcement","Tax collection"],0,"ECI is independent constitutional body conducting elections at all levels.","Election Commission: independent body. Free fair elections.");
  add(3,"Governance","Judicial review means:",["Courts can examine laws for constitutional validity and strike down unconstitutional ones","Judges reviewing each other","Parliament reviews courts","Executive reviews judiciary"],0,"If a law violates fundamental rights courts can declare it void.","Judicial review: courts check laws against Constitution. Key safeguard.");
  add(3,"Women","The Domestic Violence Act protects:",["Women in any domestic relationship — wives mothers sisters daughters","Only married women","Only women with children","Only women filing FIR first"],0,"Covers physical emotional sexual and economic abuse.","DV Act: all domestic relationships. All types of abuse covered.");
  add(3,"Women","Sexual harassment at workplace — ICC is mandatory for:",["Every organization with 10 or more employees under POSH Act","Only IT companies","Only government offices","Only large corporations"],0,"Internal Complaints Committee must be constituted under POSH Act 2013.","POSH Act: 10+ employees = must have ICC. Zero tolerance.");
  add(4,"Security","A password manager helps by:",["Generating and storing unique strong passwords for every account","Making passwords shorter","Sharing passwords with friends","Remembering one weak password"],0,"You only remember one master password. Manager handles unique passwords per site.","Password manager: one master password. Unique strong passwords everywhere.");
  add(4,"Security","Software updates should be installed:",["Promptly as they patch security vulnerabilities hackers know about","Never","Only once a year","Only when forced"],0,"Delaying updates leaves known holes open for attackers.","Update NOW not later. Hackers exploit known vulnerabilities fast.");
  add(4,"Security","Juice jacking at public USB stations involves:",["Malware installation or data theft through modified USB ports","Only slow charging","No risk","Only old phones"],0,"Use your own charger. Or carry a USB data blocker.","Public USB can steal data. Use YOUR charger or USB data blocker.");
  add(4,"Security","A phishing email is identified by:",["Urgency pressure generic greetings suspicious links and requests for personal info","Perfect grammar always means phishing","Only by email provider","Phishing is always obvious"],0,"Look for: urgency generic greeting suspicious sender address.","Phishing: urgency + generic greeting + suspicious link = don't click.");
  add(4,"Security","Two-factor authentication is most secure with:",["An authenticator app or hardware key rather than SMS","SMS codes only","Email verification","A second password"],0,"SMS codes can be intercepted via SIM swapping. Authenticator apps work offline.","Use Google Authenticator or Authy. More secure than SMS 2FA.");
  add(4,"Privacy","Your digital footprint includes:",["Everything online — searches posts purchases location data even deleted content","Only social media posts","Only emails","Only photos"],0,"Companies employers and hackers can use your digital footprint.","Digital footprint is permanent. Think before you post click or search.");
  add(4,"Privacy","Incognito browsing:",["Only prevents browser from saving local history — ISP and sites still track you","Makes you anonymous online","Blocks all cookies forever","Encrypts traffic like VPN"],0,"ISP employer and websites still see everything in incognito.","Incognito = local privacy only. ISP and websites still see you.");
  add(4,"Privacy","Location sharing on social media should be:",["Carefully limited — real-time location reveals whereabouts to strangers","Always on","Never a concern","Mandatory"],0,"Posting live location helps stalkers and burglars.","Turn OFF live location in posts. Share only with trusted contacts.");
  add(4,"Privacy","End-to-end encryption means:",["Only sender and recipient can read messages — not even the app company","Only sender reads it","Messages backed up to cloud","Messages faster"],0,"WhatsApp Signal use E2E encryption. Even if intercepted can't be decoded.","E2E encrypted: only you and recipient can read. Not even the app.");
  add(4,"AI","AI hallucinations means:",["AI generating confident but factually incorrect information","AI dreaming","Computer overheating","AI refusing to answer"],0,"Large language models produce plausible but sometimes completely wrong facts.","AI can be confidently wrong. Always verify important AI outputs.");
  add(4,"AI","Deepfake technology can:",["Create realistic fake videos making people appear to say things they never said","Only produce low quality","Only governments use it","Only computers affected"],0,"Deepfakes threaten elections relationships and trust.","Deepfakes: realistic fake video. Verify before believing.");
  add(4,"AI","AI bias comes from:",["Historical biases in the training data used to build the AI","AI being evil","Random errors","User manipulation"],0,"If training data has biases AI amplifies them.","AI inherits human biases from data. Always question AI decisions.");
  add(4,"Social Media","The filter bubble effect means:",["Algorithms only show content matching your views limiting diverse perspectives","Photo filters","Spam filtering","Content moderation"],0,"Break the bubble: follow diverse sources read opposing viewpoints.","Filter bubble traps you in echo chambers. Seek diverse views actively.");
  add(4,"Social Media","Cyberbullying differs from traditional bullying because:",["It follows victims home spreads virally and happens 24/7","Less harmful","Only adults affected","Always involves physical threats"],0,"Save evidence block report and tell trusted adult.","Cyberbullying: screenshot → block → report → tell trusted adult.");
  add(4,"Social Media","Doom-scrolling means:",["Compulsively consuming negative news despite it worsening your mood","Scrolling fun content","A social media game","Fast scrolling technique"],0,"Set time limits on news apps. Limit to 15 min twice daily.","Caught doom-scrolling? Set timer. 15 min news twice daily max.");
  add(4,"Fake News","The most reliable way to verify news:",["Cross-check across multiple credible independent sources","Check how many shared it","If headline is convincing","If it confirms your beliefs"],0,"No single source is infallible. Cross-reference established outlets.","Before sharing: check 3+ credible sources. One source = be skeptical.");
  add(4,"Fake News","Fact-checking websites in India include:",["Alt News Boom FactChecker and India Today Fact Check","Only Wikipedia","Only social media comments","None exist in India"],0,"Before sharing sensational news check these sites.","Use Alt News or Boom to verify. If only one source claims it be skeptical.");
  add(4,"Digital Life","Blue light from screens before bed:",["Suppresses melatonin disrupting sleep","No effect on sleep","Helps sleep","Only affects children"],0,"Use night mode after 8 PM. Stop screens 1 hour before bed.","Blue light = less melatonin = bad sleep. Night mode ON after 8 PM.");
  add(4,"Digital Life","Digital minimalism means:",["Intentionally using only technology that truly adds value to your life","Owning zero devices","Having cheapest phone","Never using internet"],0,"Keep apps that serve you. Delete those that consume time and attention.","Keep what adds value. Delete what steals your time.");
  add(9,"Logic","Cherry-picking data means:",["Choosing only evidence supporting your argument while ignoring contradicting evidence","Selecting best quality data","Organizing data","Collecting all data"],0,"Advertisers and politicians cherry-pick statistics for their narrative.","Watch for cherry-picked stats. Ask: what data are they NOT showing?");
  add(9,"Logic","The Texas sharpshooter fallacy:",["Drawing conclusions first then finding data to support them ignoring the rest","Expert marksmanship","Texas politics","Statistical accuracy"],0,"Like shooting at a barn then painting the target around the holes.","Conclusion first evidence second = bad reasoning.");
  add(9,"Logic","Selection bias means:",["Sample studied is not representative of the population leading to skewed results","Selecting best candidates","Random sampling","Equal representation"],0,"Online polls are biased: only capture responders' opinions.","Ask: does this sample represent the whole population?");
  add(9,"Logic","The Gambler's Fallacy is:",["Believing past random events influence future ones like a coin being due for heads","Gambling always loses","Skill determines outcomes","All gambling is fair"],0,"Each coin flip is independent. 10 heads doesn't make tails more likely.","Each random event is independent. Past doesn't influence future flips.");
  add(9,"Logic","A red herring is:",["An irrelevant topic introduced to distract from the real issue","A strong counterpoint","Valid concern","Evidence"],0,"Politicians use red herrings to avoid answering difficult questions.","Red herring: distraction from real issue. Stay focused on the topic.");
  add(9,"Logic","Whataboutism deflects by:",["Pointing to someone else's wrongdoing instead of addressing the criticism","Addressing directly","Providing evidence","Accepting responsibility"],0,"Both things can be wrong. Whataboutism avoids accountability.","Whataboutism: both things can be wrong. Address YOUR issue.");
  add(9,"Logic","Post hoc fallacy assumes:",["Because B happened after A then A must have caused B","Proper logical order","Events are unrelated","Time doesn't matter"],0,"Lucky socks didn't cause the victory. Sequence doesn't prove causation.","After is not because of. Sequence doesn't prove causation.");
  add(9,"Logic","The burden of proof falls on:",["The person making a claim to provide evidence","Person questioning","Nobody","The audience"],0,"Extraordinary claims need extraordinary evidence. Claimer must prove.","Can't prove a negative. Burden is on whoever makes the claim.");
  add(9,"Bias","Availability heuristic makes people:",["Overestimate likelihood of events that are easily recalled like plane crashes","Remember accurately","Forget everything","Think rationally"],0,"We fear plane crashes more than car accidents despite cars being far more deadly.","We overestimate vivid risks and underestimate common boring ones.");
  add(9,"Bias","The endowment effect means:",["People value things they own more than identical things they don't own","Giving away easily","Buying more","Ignoring possessions"],0,"We overvalue our old phone but wouldn't pay same for someone else's identical one.","You overvalue what you own. Be objective when deciding to keep or sell.");
  add(9,"Bias","Status quo bias is:",["Preference for current state even when better alternatives exist","Preference for change","High social status","New experiences"],0,"People stick with bank phone plan and habits even when switching saves money.","We prefer familiar even when change is better. Audit your choices.");
  add(9,"Bias","The Barnum effect explains why people believe:",["Vague descriptions like horoscopes that seem personal but apply to everyone","Scientific studies","Weather forecasts","Expert opinions"],0,"You sometimes feel insecure applies to every human. That's why horoscopes work.","Horoscopes work because they're vague enough to fit anyone.");
  add(9,"Bias","Negativity bias means:",["Humans give more weight to negative experiences than equally positive ones","Being always negative","Ignoring negatives","Only remembering good"],0,"One criticism stings more than ten compliments. Evolution wired us for threats.","One insult hurts more than ten compliments. Counter negativity bias consciously.");
  add(9,"Bias","Ingroup bias makes people:",["Favor their own group while being less favorable to outsiders","Treat everyone equally","Hate own group","Have no preferences"],0,"Drives tribalism from sports to politics to nationalism.","We naturally favor our group. Recognize bias. Judge people individually.");
  add(9,"Decision","Analysis paralysis is overcome by:",["Setting a deadline and accepting perfect information is rarely available","Gathering infinite data","Avoiding analysis","Always flipping coins"],0,"Good decision on time beats perfect decision too late.","80% info is enough. Set deadline. Decide. Perfect is enemy of good.");
  add(9,"Decision","The 10-10-10 rule asks:",["How will you feel in 10 minutes 10 months and 10 years about this decision","What 10 people think","If it takes 10 steps","Cost times 10"],0,"Great for emotional decisions. What seems huge now often doesn't matter in 10 months.","Big decision? Will it matter in 10 min? 10 months? 10 years?");
  add(9,"Decision","Second-order thinking considers:",["Not just direct consequences but the consequences of those consequences","Only immediate effects","Second opinions","Two options"],0,"Dessert tastes good (1st order). Daily dessert causes weight gain (2nd order).","Think two steps ahead. What happens after what happens?");
  add(9,"Decision","Mental models are:",["Thinking frameworks that help understand the world and make better decisions","3D brain scans","Only for scientists","Computer simulations"],0,"Examples: first principles inversion 80/20 second-order thinking.","Build mental model toolkit: 80/20 inversion first principles.");
  add(9,"Ethics","The bystander effect means:",["People are less likely to help when others are present assuming someone else will act","Bystanders always help","Standing by is safe","Witnesses are accurate"],0,"In crowds point at ONE person and say YOU call 112.","Bystander effect: point at ONE person. Say YOU call 112.");
  add(9,"Ethics","The tragedy of the commons:",["Individual self-interest depleting shared resources harming everyone","Well-maintained spaces","Unlimited resources","Perfect cooperation"],0,"Overfishing pollution traffic: rational individuals causing collective disaster.","Shared resources + unchecked self-interest = everyone loses.");
  add(9,"Ethics","Cognitive dissonance is:",["Mental discomfort when actions contradict beliefs","Harmonious thinking","Brain disorder","Perfect logic"],0,"Knowing smoking kills but continuing creates internal tension.","Actions vs beliefs = tension. Use it as signal to change.");
  add(10,"Governance","Question Hour in Parliament is:",["The first hour when MPs question ministers about government functioning","A quiz show","A private session","An informal chat"],0,"Holds government accountable. Happens at start of each sitting.","Question Hour: MPs hold ministers accountable. Key democracy tool.");
  add(10,"Governance","FSSAI regulates:",["Food safety and standards in India","Factory safety","Financial services","Foreign policy"],0,"FSSAI licenses food businesses. Look for the FSSAI logo on packaged food.","FSSAI logo = safety checked. Look for license number on food.");
  add(10,"Governance","TRAI regulates:",["Telecom and broadcasting in India","Transport","Tourism","Trade"],0,"Ensures fair telecom practices and protects consumer interests.","TRAI: your telecom rights. File complaints on their portal.");
  add(10,"Governance","A no-confidence motion can only be moved in:",["Lok Sabha","Rajya Sabha","Both houses","State assembly"],0,"If passed by majority the government must resign.","No-confidence: Lok Sabha only. If passed government falls.");
  add(10,"Governance","The Vice President chairs:",["Rajya Sabha as its ex-officio Chairman","Lok Sabha","NITI Aayog","Supreme Court"],0,"VP presides over Rajya Sabha proceedings.","VP = Chairman Rajya Sabha. Speaker = head Lok Sabha.");
  add(10,"Governance","Speaker of Lok Sabha votes:",["Only in case of a tie as casting vote","On every issue","Never","Only money bills"],0,"Speaker maintains neutrality. Votes only to break deadlock.","Speaker votes only to break tie. Maintains neutrality.");
  add(10,"Governance","Minimum age for President of India:",["35 years","25","40","50"],0,"Must be citizen qualified for Lok Sabha membership.","President: min 35. PM: min 25. Rajya Sabha: min 30.");
  add(10,"International","WTO is headquartered in:",["Geneva Switzerland","New York","Washington DC","Brussels"],0,"WTO deals with international trade rules.","WTO: Geneva. UN: New York. IMF/World Bank: Washington.");
  add(10,"International","WHO is headquartered in:",["Geneva Switzerland","New York","London","Paris"],0,"World Health Organization coordinates global public health.","WHO: Geneva. UN's global health authority.");
  add(10,"International","G20 represents approximately:",["85% of global GDP","50%","30%","95%"],0,"India hosted G20 presidency in 2023.","G20: 85% of world GDP. India hosted 2023. Powerful forum.");
